const Q_SR_SPECIALIST=[{"id": "srs111001", "state": "AU", "section": "sr_specialist", "grade": "11", "topic": "Complex Numbers — Basics", "difficulty": "hard", "style": "standard", "paper": "G11-S1", "q": "What is the value of i² (where i is the imaginary unit)?", "options": ["1", "-1", "i", "-i"], "answer": 1, "exp": "By definition, the imaginary unit i satisfies i² = -1.", "hint": "Remember the fundamental defining property of the imaginary unit."}, {"id": "srs111002", "state": "AU", "section": "sr_specialist", "grade": "11", "topic": "Complex Numbers — Arithmetic", "difficulty": "hard", "style": "standard", "paper": "G11-S1", "q": "Simplify: (3 + 2i) + (1 − 4i)", "options": ["4 + 2i", "4 − 2i", "2 + 6i", "2 − 6i"], "answer": 1, "exp": "Add the real parts and the imaginary parts separately: (3+1) + (2−4)i = 4 − 2i.", "hint": "Combine the real parts together, and the imaginary parts together, separately."}, {"id": "srs111003", "state": "AU", "section": "sr_specialist", "grade": "11", "topic": "Complex Numbers — Arithmetic", "difficulty": "hard", "style": "standard", "paper": "G11-S1", "q": "Simplify: (3 + 2i) − (1 − 4i)", "options": ["4 − 2i", "4 + 2i", "2 + 6i", "2 − 6i"], "answer": 2, "exp": "Subtract real parts and imaginary parts separately: (3−1) + (2−(-4))i = 2 + 6i.", "hint": "Be careful with the signs when subtracting a negative imaginary part."}, {"id": "srs111004", "state": "AU", "section": "sr_specialist", "grade": "11", "topic": "Complex Numbers — Arithmetic", "difficulty": "hard", "style": "standard", "paper": "G11-S1", "q": "Simplify: (3 + 2i)(1 − 4i)", "options": ["3 − 8i", "11 − 10i", "3 + 10i", "11 + 10i"], "answer": 1, "exp": "Step 1: Expand using FOIL: 3(1)+3(-4i)+2i(1)+2i(-4i) = 3−12i+2i−8i². Step 2: Since i²=-1: 3−12i+2i+8 = 11−10i.", "hint": "Expand carefully like a normal binomial product, then simplify using i²=-1."}, {"id": "srs111005", "state": "AU", "section": "sr_specialist", "grade": "11", "topic": "Complex Numbers — Conjugates", "difficulty": "hard", "style": "standard", "paper": "G11-S1", "q": "Simplify: (2 + 3i)(2 − 3i)", "options": ["4 − 9i", "4 + 9", "13", "4 − 9"], "answer": 2, "exp": "Step 1: Expand: 4−6i+6i−9i². Step 2: The imaginary terms cancel, and since i²=-1: 4+9=13.", "hint": "Notice this is a product of conjugates — the imaginary parts will cancel out completely."}, {"id": "srs111006", "state": "AU", "section": "sr_specialist", "grade": "11", "topic": "Complex Numbers — Conjugates", "difficulty": "hard", "style": "standard", "paper": "G11-S1", "q": "What is the complex conjugate of z = 3 + 4i?", "options": ["3 − 4i", "-3 + 4i", "-3 − 4i", "4 + 3i"], "answer": 0, "exp": "The complex conjugate of a+bi is a−bi, found by reversing the sign of the imaginary part. For 3+4i, this is 3−4i.", "hint": "Keep the real part the same, and reverse the sign of the imaginary part."}, {"id": "srs111007", "state": "AU", "section": "sr_specialist", "grade": "11", "topic": "Complex Numbers — Modulus", "difficulty": "hard", "style": "standard", "paper": "G11-S1", "q": "What is the modulus (absolute value) of z = 3 + 4i?", "options": ["3", "4", "5", "7"], "answer": 2, "exp": "Step 1: |a+bi| = √(a²+b²). Step 2: √(3²+4²) = √(9+16) = √25 = 5.", "hint": "Use the formula √(real part squared + imaginary part squared)."}, {"id": "srs111008", "state": "AU", "section": "sr_specialist", "grade": "11", "topic": "Complex Numbers — Division", "difficulty": "hard", "style": "standard", "paper": "G11-S1", "q": "Simplify: (1 + 2i)/(3 − i), giving your answer in the form a + bi.", "options": ["1/10 + 7i/10", "1/8 + i/8", "1/10 − 7i/10", "7/10 + i/10"], "answer": 0, "exp": "Step 1: Multiply numerator and denominator by the conjugate of the denominator (3+i): [(1+2i)(3+i)]/[(3−i)(3+i)]. Step 2: Numerator: 3+i+6i+2i²=3+7i−2=1+7i. Step 3: Denominator: 9+1=10. Result: 1/10 + 7i/10.", "hint": "Multiply both the numerator and denominator by the conjugate of the denominator to eliminate i from the bottom."}, {"id": "srs111009", "state": "AU", "section": "sr_specialist", "grade": "11", "topic": "Complex Numbers — Solving Equations", "difficulty": "hard", "style": "standard", "paper": "G11-S1", "q": "Solve the equation x² + 4 = 0 over the complex numbers.", "options": ["x = ±2", "x = ±2i", "x = ±4i", "no solutions exist"], "answer": 1, "exp": "Step 1: x² = -4. Step 2: Taking the square root of both sides: x = ±√(-4) = ±2i.", "hint": "Rearrange to isolate x², then take the square root, remembering √(-1)=i."}, {"id": "srs111010", "state": "AU", "section": "sr_specialist", "grade": "11", "topic": "Complex Numbers — Solving Equations", "difficulty": "hard", "style": "standard", "paper": "G11-S1", "q": "Solve the equation x² − 2x + 5 = 0 over the complex numbers.", "options": ["x = 1 ± 2i", "x = 1 ± 4i", "x = -1 ± 2i", "x = 2 ± i"], "answer": 0, "exp": "Step 1: Using the quadratic formula: x = (2 ± √(4−20))/2 = (2 ± √(-16))/2. Step 2: √(-16) = 4i, so x = (2 ± 4i)/2 = 1 ± 2i.", "hint": "Use the quadratic formula — when the discriminant is negative, this leads to complex solutions."}, {"id": "srs111011", "state": "AU", "section": "sr_specialist", "grade": "11", "topic": "Complex Numbers — Argument", "difficulty": "hard", "style": "standard", "paper": "G11-S1", "q": "What is the argument (angle) of the complex number z = 1 + i, in degrees?", "options": ["30°", "45°", "60°", "90°"], "answer": 1, "exp": "The argument is the angle the complex number makes with the positive real axis. For 1+i, this angle is arctan(1/1)=45°, since both real and imaginary parts are equal and positive.", "hint": "Think about the angle formed in the complex plane, using the real and imaginary parts as coordinates (1,1)."}, {"id": "srs111012", "state": "AU", "section": "sr_specialist", "grade": "11", "topic": "Complex Numbers — Basics", "difficulty": "hard", "style": "standard", "paper": "G11-S1", "q": "Which best describes the 'imaginary unit', i?", "options": ["a real number equal to -1", "a number defined such that i² = -1, since no real number satisfies this", "a synonym for any negative number", "a unit used only in physics, not mathematics"], "answer": 1, "exp": "The imaginary unit i is defined specifically so that i² = -1, filling a gap since no real number, when squared, gives a negative result.", "hint": "Think about why this special number had to be DEFINED, rather than already existing among the real numbers."}, {"id": "srs111013", "state": "AU", "section": "sr_specialist", "grade": "11", "topic": "Complex Numbers — Powers of i", "difficulty": "hard", "style": "standard", "paper": "G11-S1", "q": "Simplify: i³", "options": ["1", "-1", "i", "-i"], "answer": 3, "exp": "Step 1: i³ = i²×i = (-1)×i = -i.", "hint": "Break i³ into i²×i, then substitute the known value of i²."}, {"id": "srs111014", "state": "AU", "section": "sr_specialist", "grade": "11", "topic": "Complex Numbers — Powers of i", "difficulty": "hard", "style": "standard", "paper": "G11-S1", "q": "Simplify: i⁴", "options": ["1", "-1", "i", "-i"], "answer": 0, "exp": "Step 1: i⁴ = (i²)² = (-1)² = 1.", "hint": "Rewrite i⁴ as (i²) squared, then substitute the known value of i²."}, {"id": "srs111015", "state": "AU", "section": "sr_specialist", "grade": "11", "topic": "Complex Numbers — Powers of i", "difficulty": "hard", "style": "standard", "paper": "G11-S1", "q": "What is the value of i¹⁰? (Hint: powers of i repeat in a cycle of 4.)", "options": ["1", "-1", "i", "-i"], "answer": 1, "exp": "Step 1: Since powers of i cycle every 4 (i¹=i, i²=-1, i³=-i, i⁴=1), find the remainder of 10÷4, which is 2. Step 2: i¹⁰ = i² = -1.", "hint": "Find the remainder when the exponent is divided by 4, then match it to the corresponding value in the cycle."}, {"id": "srs111016", "state": "AU", "section": "sr_specialist", "grade": "11", "topic": "Complex Numbers — Conjugates", "difficulty": "hard", "style": "standard", "paper": "G11-S1", "q": "For a complex number z = a + bi, what is z × z̄ (the product of z and its conjugate) always equal to?", "options": ["a² − b²", "a² + b², which equals |z|²", "2a", "2bi"], "answer": 1, "exp": "For any complex number z=a+bi, z×z̄ = (a+bi)(a−bi) = a²+b², which is always a real, non-negative number, equal to the square of the modulus |z|².", "hint": "Multiply out (a+bi)(a−bi) — notice the imaginary terms always cancel."}, {"id": "srs111017", "state": "AU", "section": "sr_specialist", "grade": "11", "topic": "Complex Numbers — Division", "difficulty": "hard", "style": "standard", "paper": "G11-S1", "q": "Which best describes why complex conjugates are useful when dividing complex numbers?", "options": ["conjugates have no real use in division", "multiplying both the numerator and denominator by the conjugate of the denominator eliminates the imaginary part from the denominator, since z×z̄ is always real", "conjugates are only used for addition, not division", "division of complex numbers is impossible"], "answer": 1, "exp": "Multiplying both the numerator and denominator by the conjugate of the denominator eliminates the imaginary part from the denominator (since z×z̄ is always a real number), allowing the result to be expressed cleanly in the form a+bi.", "hint": "Think about how multiplying by the conjugate turns the denominator into a purely real number."}, {"id": "srs111018", "state": "AU", "section": "sr_specialist", "grade": "11", "topic": "Complex Numbers — Argand Diagrams", "difficulty": "hard", "style": "standard", "paper": "G11-S1", "q": "On the complex plane (Argand diagram), what do the horizontal and vertical axes typically represent?", "options": ["both axes represent the real part", "the horizontal axis represents the real part, and the vertical axis represents the imaginary part", "the horizontal axis represents the imaginary part, and the vertical axis represents the real part", "neither axis has a specific meaning"], "answer": 1, "exp": "On an Argand diagram, the horizontal axis represents the real part of a complex number, and the vertical axis represents the imaginary part.", "hint": "Think about which part of a complex number (a+bi) is typically plotted along each axis."}, {"id": "srs111019", "state": "AU", "section": "sr_specialist", "grade": "11", "topic": "Complex Numbers — Argand Diagrams", "difficulty": "hard", "style": "standard", "paper": "G11-S1", "q": "Where would the complex number z = -3 + 2i be located on an Argand diagram?", "options": ["in the first quadrant", "in the second quadrant", "in the third quadrant", "in the fourth quadrant"], "answer": 1, "exp": "Since the real part is negative (-3) and the imaginary part is positive (2), this point lies in the second quadrant (upper-left) of the Argand diagram.", "hint": "Think about the sign of the real part (horizontal) and the imaginary part (vertical) to locate the correct quadrant."}, {"id": "srs111020", "state": "AU", "section": "sr_specialist", "grade": "11", "topic": "Complex Numbers — Arithmetic", "difficulty": "hard", "style": "standard", "paper": "G11-S1", "q": "Simplify: 2i × 3i", "options": ["6", "-6", "6i", "-6i"], "answer": 1, "exp": "Step 1: 2i × 3i = 6i². Step 2: Since i²=-1: 6×(-1) = -6.", "hint": "Multiply the coefficients and the i terms separately, then simplify i² to -1."}, {"id": "srs111021", "state": "AU", "section": "sr_specialist", "grade": "11", "topic": "Complex Numbers — Modulus", "difficulty": "hard", "style": "standard", "paper": "G11-S1", "q": "What is the modulus of the complex number z = -5 + 12i?", "options": ["7", "13", "17", "60"], "answer": 1, "exp": "Step 1: |a+bi| = √(a²+b²). Step 2: √((-5)²+12²) = √(25+144) = √169 = 13.", "hint": "Use the modulus formula, remembering to square the real part even if it's negative."}, {"id": "srs111022", "state": "AU", "section": "sr_specialist", "grade": "11", "topic": "Complex Numbers — Basics", "difficulty": "hard", "style": "standard", "paper": "G11-S1", "q": "Which best describes a 'purely imaginary' number?", "options": ["a complex number with a real part of zero (and a non-zero imaginary part)", "a complex number with an imaginary part of zero", "a synonym for any negative number", "a complex number that does not actually exist"], "answer": 0, "exp": "A purely imaginary number has a real part of zero, taking the form bi (where b is a non-zero real number), such as 5i or -3i.", "hint": "Think about a complex number with nothing in its 'real' component, only an imaginary part."}, {"id": "srs111023", "state": "AU", "section": "sr_specialist", "grade": "11", "topic": "Complex Numbers — Solving Equations", "difficulty": "hard", "style": "standard", "paper": "G11-S1", "q": "Solve x² + 9 = 0 over the complex numbers.", "options": ["x = ±3", "x = ±3i", "x = ±9i", "no solution exists"], "answer": 1, "exp": "Step 1: x² = -9. Step 2: x = ±√(-9) = ±3i.", "hint": "Isolate x², then take the square root, remembering to include i."}, {"id": "srs111024", "state": "AU", "section": "sr_specialist", "grade": "11", "topic": "Complex Numbers — Polar Form Introduction", "difficulty": "hard", "style": "standard", "paper": "G11-S1", "q": "For the complex number z = 5(cos60° + i sin60°), what is the modulus of z?", "options": ["1", "5", "30", "60"], "answer": 1, "exp": "When a complex number is written in the form r(cosθ + isinθ), r directly represents the modulus. Here, r=5.", "hint": "Identify the coefficient out the front of the trigonometric expression — this directly represents the modulus."}, {"id": "srs111025", "state": "AU", "section": "sr_specialist", "grade": "11", "topic": "Complex Numbers — Solving Equations", "difficulty": "hard", "style": "standard", "paper": "G11-S1", "q": "Which best describes why every quadratic equation with real coefficients has either two real roots, or two complex conjugate roots (but never just one isolated complex root)?", "options": ["this is simply a coincidence with no underlying reason", "complex roots of a polynomial with real coefficients always occur in conjugate pairs, due to how the quadratic formula's ± symbol interacts with a negative discriminant", "quadratic equations can have exactly one complex root with no partner", "this rule only applies to cubic equations, not quadratics"], "answer": 1, "exp": "When a quadratic equation with real coefficients has a negative discriminant, the ± in the quadratic formula naturally produces two complex roots that are conjugates of each other (e.g. 1+2i and 1−2i) — complex roots of real-coefficient polynomials always occur in such conjugate pairs.", "hint": "Think about how the ± sign in the quadratic formula, combined with a negative number under the square root, naturally creates a conjugate pair."}, {"id": "srs112001", "state": "AU", "section": "sr_specialist", "grade": "11", "topic": "Vectors — Addition", "difficulty": "hard", "style": "standard", "paper": "G11-S2", "q": "Given vectors a = (3, 4) and b = (1, -2), find a + b.", "options": ["(4, 2)", "(2, 6)", "(4, -8)", "(3, -8)"], "answer": 0, "exp": "Add corresponding components: (3+1, 4+(-2)) = (4, 2).", "hint": "Add the corresponding x-components together, and the corresponding y-components together."}, {"id": "srs112002", "state": "AU", "section": "sr_specialist", "grade": "11", "topic": "Vectors — Subtraction", "difficulty": "hard", "style": "standard", "paper": "G11-S2", "q": "Given vectors a = (3, 4) and b = (1, -2), find a − b.", "options": ["(4, 2)", "(2, 6)", "(2, -6)", "(4, -2)"], "answer": 1, "exp": "Subtract corresponding components: (3-1, 4-(-2)) = (2, 6).", "hint": "Subtract the corresponding components, being careful with the signs."}, {"id": "srs112003", "state": "AU", "section": "sr_specialist", "grade": "11", "topic": "Vectors — Magnitude", "difficulty": "hard", "style": "standard", "paper": "G11-S2", "q": "Find the magnitude (length) of the vector a = (3, 4).", "options": ["3", "4", "5", "7"], "answer": 2, "exp": "Step 1: Magnitude = √(3²+4²). Step 2: √(9+16) = √25 = 5.", "hint": "Use the formula: magnitude = √(x²+y²), similar to Pythagoras' theorem."}, {"id": "srs112004", "state": "AU", "section": "sr_specialist", "grade": "11", "topic": "Vectors — Magnitude", "difficulty": "hard", "style": "standard", "paper": "G11-S2", "q": "Find the magnitude of the vector b = (1, -2).", "options": ["√3", "√5", "3", "5"], "answer": 1, "exp": "Step 1: Magnitude = √(1²+(-2)²). Step 2: √(1+4) = √5.", "hint": "Use the formula: magnitude = √(x²+y²)."}, {"id": "srs112005", "state": "AU", "section": "sr_specialist", "grade": "11", "topic": "Vectors — Scalar Multiplication", "difficulty": "hard", "style": "standard", "paper": "G11-S2", "q": "Given vector a = (3, 4), find 3a.", "options": ["(6, 7)", "(9, 12)", "(3, 12)", "(9, 4)"], "answer": 1, "exp": "Multiply each component by the scalar: 3×(3,4) = (9, 12).", "hint": "Multiply every component of the vector by the scalar."}, {"id": "srs112006", "state": "AU", "section": "sr_specialist", "grade": "11", "topic": "Vectors — Dot Product", "difficulty": "hard", "style": "standard", "paper": "G11-S2", "q": "Given vectors a = (3, 4) and b = (1, -2), find the dot product a · b.", "options": ["-5", "5", "7", "11"], "answer": 0, "exp": "Step 1: a·b = (3×1) + (4×(-2)). Step 2: 3 + (-8) = -5.", "hint": "Multiply the corresponding components together, then add the results."}, {"id": "srs112007", "state": "AU", "section": "sr_specialist", "grade": "11", "topic": "Vectors — Dot Product", "difficulty": "hard", "style": "standard", "paper": "G11-S2", "q": "Which formula correctly calculates the dot product of vectors a = (a₁, a₂) and b = (b₁, b₂)?", "options": ["a·b = a₁b₂ + a₂b₁", "a·b = a₁b₁ + a₂b₂", "a·b = a₁b₁ − a₂b₂", "a·b = (a₁+a₂)(b₁+b₂)"], "answer": 1, "exp": "The dot product of two vectors is found by multiplying corresponding components and adding the results: a·b = a₁b₁ + a₂b₂.", "hint": "Multiply MATCHING components together (first with first, second with second), then add."}, {"id": "srs112008", "state": "AU", "section": "sr_specialist", "grade": "11", "topic": "Vectors — Dot Product", "difficulty": "hard", "style": "standard", "paper": "G11-S2", "q": "Two vectors e = (2, 3) and f = (3, -2) have a dot product of e·f = 0. What does this indicate about the two vectors?", "options": ["the vectors are parallel", "the vectors are perpendicular (orthogonal) to each other", "the vectors are identical", "one of the vectors must be the zero vector"], "answer": 1, "exp": "A dot product of exactly 0 indicates that the two vectors are perpendicular (orthogonal) to each other.", "hint": "Remember the special geometric meaning when a dot product equals exactly zero."}, {"id": "srs112009", "state": "AU", "section": "sr_specialist", "grade": "11", "topic": "Vectors — Unit Vectors", "difficulty": "hard", "style": "standard", "paper": "G11-S2", "q": "Find the unit vector in the same direction as a = (3, 4).", "options": ["(3, 4)", "(3/5, 4/5)", "(1, 1)", "(0.5, 0.5)"], "answer": 1, "exp": "Step 1: The magnitude of a is 5. Step 2: Divide each component by the magnitude: (3/5, 4/5).", "hint": "Divide each component of the vector by its own magnitude."}, {"id": "srs112010", "state": "AU", "section": "sr_specialist", "grade": "11", "topic": "Vectors — Concepts", "difficulty": "hard", "style": "standard", "paper": "G11-S2", "q": "What is a 'unit vector'?", "options": ["a vector with a magnitude of exactly 0", "a vector with a magnitude of exactly 1", "a vector with all components equal to 1", "a vector that always points along the x-axis"], "answer": 1, "exp": "A unit vector is a vector with a magnitude (length) of exactly 1, often used to indicate direction without regard to size.", "hint": "Think about a vector whose length has been standardised to exactly one unit."}, {"id": "srs112011", "state": "AU", "section": "sr_specialist", "grade": "11", "topic": "Vectors — Dot Product", "difficulty": "hard", "style": "standard", "paper": "G11-S2", "q": "Given vectors c = (2, 5) and d = (-3, 1), find c · d.", "options": ["-13", "-1", "1", "13"], "answer": 1, "exp": "Step 1: c·d = (2×-3)+(5×1). Step 2: -6+5 = -1.", "hint": "Multiply corresponding components, then add the results."}, {"id": "srs112012", "state": "AU", "section": "sr_specialist", "grade": "11", "topic": "Vectors — Angle Between Vectors", "difficulty": "hard", "style": "standard", "paper": "G11-S2", "q": "Using the dot product formula a·b = |a||b|cos(θ), find the angle θ between vectors a = (3, 4) and b = (1, -2), given a·b = -5, |a|=5, and |b|=√5.", "options": ["about 27°", "about 63°", "about 117°", "about 153°"], "answer": 2, "exp": "Step 1: cos(θ) = (a·b)/(|a||b|) = -5/(5×√5) = -1/√5. Step 2: θ = cos⁻¹(-1/√5) ≈ 117°.", "hint": "Rearrange the dot product formula to solve for cos(θ), then take the inverse cosine."}, {"id": "srs112013", "state": "AU", "section": "sr_specialist", "grade": "11", "topic": "Vectors — 3D Vectors", "difficulty": "hard", "style": "standard", "paper": "G11-S2", "q": "Given 3D vectors g = (1, 2, 3) and h = (4, -1, 2), find g + h.", "options": ["(5, 1, 5)", "(5, 1, 1)", "(3, -3, -1)", "(4, -2, 6)"], "answer": 0, "exp": "Add corresponding components: (1+4, 2+(-1), 3+2) = (5, 1, 5).", "hint": "Add corresponding components from each dimension separately."}, {"id": "srs112014", "state": "AU", "section": "sr_specialist", "grade": "11", "topic": "Vectors — 3D Vectors", "difficulty": "hard", "style": "standard", "paper": "G11-S2", "q": "Find the magnitude of the 3D vector g = (1, 2, 3).", "options": ["√6", "√14", "6", "14"], "answer": 1, "exp": "Step 1: Magnitude = √(1²+2²+3²). Step 2: √(1+4+9) = √14.", "hint": "Extend the magnitude formula to three dimensions: √(x²+y²+z²)."}, {"id": "srs112015", "state": "AU", "section": "sr_specialist", "grade": "11", "topic": "Vectors — 3D Vectors", "difficulty": "hard", "style": "standard", "paper": "G11-S2", "q": "Given 3D vectors g = (1, 2, 3) and h = (4, -1, 2), find g · h.", "options": ["5", "8", "9", "14"], "answer": 1, "exp": "Step 1: g·h = (1×4)+(2×-1)+(3×2). Step 2: 4−2+6 = 8.", "hint": "Multiply corresponding components across all three dimensions, then add."}, {"id": "srs112016", "state": "AU", "section": "sr_specialist", "grade": "11", "topic": "Vectors — Concepts", "difficulty": "hard", "style": "standard", "paper": "G11-S2", "q": "Which best describes the 'zero vector'?", "options": ["a vector with a magnitude of exactly 1", "a vector with all components equal to zero, and a magnitude of 0", "a vector that cannot be added to other vectors", "a vector that points exclusively along the y-axis"], "answer": 1, "exp": "The zero vector has all of its components equal to zero, resulting in a magnitude of exactly 0.", "hint": "Think about a vector representing 'no movement at all' in any direction."}, {"id": "srs112017", "state": "AU", "section": "sr_specialist", "grade": "11", "topic": "Vectors — Concepts", "difficulty": "hard", "style": "standard", "paper": "G11-S2", "q": "Which best describes two vectors that are 'parallel'?", "options": ["their dot product must equal zero", "one vector is a scalar multiple of the other (pointing in the same or exactly opposite direction)", "they must have the same magnitude", "they must be perpendicular to each other"], "answer": 1, "exp": "Two vectors are parallel if one is a scalar multiple of the other, meaning they point in the same direction (or exactly opposite directions).", "hint": "Think about vectors that point along the exact same line, even if their lengths differ."}, {"id": "srs112018", "state": "AU", "section": "sr_specialist", "grade": "11", "topic": "Vectors — Concepts", "difficulty": "hard", "style": "standard", "paper": "G11-S2", "q": "Are the vectors p = (2, 6) and q = (1, 3) parallel?", "options": ["yes, since p = 2q", "no, since their magnitudes are different", "yes, but only if they point in the same direction by coincidence", "no, since their dot product is not zero"], "answer": 0, "exp": "Since p = (2,6) = 2×(1,3) = 2q, vector p is a scalar multiple of vector q, confirming they are parallel.", "hint": "Check whether one vector can be obtained by multiplying the other by a single scalar value."}, {"id": "srs112019", "state": "AU", "section": "sr_specialist", "grade": "11", "topic": "Vectors — Applications", "difficulty": "hard", "style": "standard", "paper": "G11-S2", "q": "Which best describes vector 'displacement', as distinct from distance?", "options": ["displacement and distance always have the same value", "displacement is a vector quantity (with direction) representing the change in position, while distance is a scalar quantity representing total path length travelled", "distance is always greater than displacement", "displacement has no connection to vectors"], "answer": 1, "exp": "Displacement is a vector quantity (having both magnitude and direction) representing the change in position from start to finish, while distance is a scalar quantity representing the total path length actually travelled, regardless of direction.", "hint": "Think about the difference between 'how far you actually walked' versus 'how far you ended up from where you started, and in which direction'."}, {"id": "srs112020", "state": "AU", "section": "sr_specialist", "grade": "11", "topic": "Vectors — Applications", "difficulty": "hard", "style": "standard", "paper": "G11-S2", "q": "A position vector r(t) = (2t, 3t − 1) describes the motion of a particle. What is the particle's position at t = 2?", "options": ["(2, 5)", "(4, 5)", "(4, 6)", "(2, 6)"], "answer": 1, "exp": "Substituting t=2: r(2) = (2×2, 3×2−1) = (4, 5).", "hint": "Substitute t=2 into each component of the position vector."}, {"id": "srs112021", "state": "AU", "section": "sr_specialist", "grade": "11", "topic": "Vectors — Concepts", "difficulty": "hard", "style": "standard", "paper": "G11-S2", "q": "Which best describes a 'resultant vector'?", "options": ["a vector with zero magnitude", "the single vector that represents the combined effect of two or more vectors added together", "a synonym for a unit vector", "a vector that can never be calculated"], "answer": 1, "exp": "A resultant vector is the single vector representing the combined effect of two or more vectors added together.", "hint": "Think about the single, overall vector that results from combining several other vectors."}, {"id": "srs112022", "state": "AU", "section": "sr_specialist", "grade": "11", "topic": "Vectors — Applications", "difficulty": "hard", "style": "standard", "paper": "G11-S2", "q": "Two forces, represented by vectors (4, 0) and (0, 3), act on an object simultaneously. What is the magnitude of the resultant force?", "options": ["3", "4", "5", "7"], "answer": 2, "exp": "Step 1: Resultant vector = (4,0)+(0,3) = (4,3). Step 2: Magnitude = √(4²+3²) = √25 = 5.", "hint": "Add the two vectors together first, then find the magnitude of the resulting vector."}, {"id": "srs112023", "state": "AU", "section": "sr_specialist", "grade": "11", "topic": "Vectors — Concepts", "difficulty": "hard", "style": "standard", "paper": "G11-S2", "q": "Which best describes the geometric interpretation of vector subtraction, a − b?", "options": ["a−b has no clear geometric meaning", "a−b represents the vector that, when added to b, gives a — geometrically, the vector pointing from the tip of b to the tip of a (when both start from the same point)", "a−b is always equal to a+b", "subtraction is undefined for vectors"], "answer": 1, "exp": "a−b represents the vector that, when added to b, gives a. Geometrically, if both vectors start from the same point, a−b points from the tip of b to the tip of a.", "hint": "Think about which vector, when added to b, would give you back a."}, {"id": "srs112024", "state": "AU", "section": "sr_specialist", "grade": "11", "topic": "Vectors — Angle Between Vectors", "difficulty": "hard", "style": "standard", "paper": "G11-S2", "q": "For vectors a = (5, 0) and b = (0, 5), what is the angle between them?", "options": ["0°", "45°", "90°", "180°"], "answer": 2, "exp": "Since a·b = (5×0)+(0×5) = 0, the dot product is zero, confirming the vectors are perpendicular, with an angle of 90° between them.", "hint": "Check the dot product first — a result of zero indicates a specific, well-known angle."}, {"id": "srs112025", "state": "AU", "section": "sr_specialist", "grade": "11", "topic": "Vectors — Applications", "difficulty": "hard", "style": "standard", "paper": "G11-S2", "q": "Which best describes why vectors are particularly useful for representing physical quantities like force, velocity, and displacement?", "options": ["vectors have no practical advantage over ordinary numbers for these quantities", "these quantities have both a magnitude AND a direction, both of which vectors can represent simultaneously, unlike a single number alone", "vectors can only represent quantities with no direction", "force, velocity, and displacement have no real connection to mathematics"], "answer": 1, "exp": "Force, velocity, and displacement are all quantities that have both a magnitude and a direction — vectors can represent both of these properties simultaneously, which a single number (scalar) alone cannot do.", "hint": "Think about why simply stating 'the speed was 10' is less complete than also stating the direction of travel."}, {"id": "srs113001", "state": "AU", "section": "sr_specialist", "grade": "11", "topic": "Trigonometry — Compound Angle Formulas", "difficulty": "hard", "style": "standard", "paper": "G11-S3", "q": "Using the compound angle formula sin(A+B) = sinAcosB + cosAsinB, find the exact value of sin(75°), using A=45° and B=30°.", "options": ["(√2+√6)/4", "(√2−√6)/4", "(√3+1)/4", "√2/2"], "answer": 0, "exp": "Step 1: sin(75°) = sin(45°+30°) = sin45°cos30°+cos45°sin30°. Step 2: (√2/2)(√3/2)+(√2/2)(1/2) = (√6+√2)/4.", "hint": "Substitute the exact values for sin and cos of 45° and 30° into the compound angle formula."}, {"id": "srs113002", "state": "AU", "section": "sr_specialist", "grade": "11", "topic": "Trigonometry — Compound Angle Formulas", "difficulty": "hard", "style": "standard", "paper": "G11-S3", "q": "Which of these is the correct compound angle formula for cos(A+B)?", "options": ["cos(A+B) = cosAcosB + sinAsinB", "cos(A+B) = cosAcosB − sinAsinB", "cos(A+B) = sinAcosB + cosAsinB", "cos(A+B) = sinAcosB − cosAsinB"], "answer": 1, "exp": "The compound angle formula for cosine is cos(A+B) = cosAcosB − sinAsinB.", "hint": "Remember that the cosine compound angle formula uses a MINUS sign, unlike the sine version."}, {"id": "srs113003", "state": "AU", "section": "sr_specialist", "grade": "11", "topic": "Trigonometry — Double Angle Formulas", "difficulty": "hard", "style": "standard", "paper": "G11-S3", "q": "Using the double angle formula sin(2x) = 2sinxcosx, find sin(2x) given sinx = 3/5 and cosx = 4/5.", "options": ["7/25", "12/25", "24/25", "7/5"], "answer": 2, "exp": "Step 1: sin(2x) = 2×(3/5)×(4/5). Step 2: 2×12/25 = 24/25.", "hint": "Substitute the given values directly into the double angle formula."}, {"id": "srs113004", "state": "AU", "section": "sr_specialist", "grade": "11", "topic": "Trigonometry — Double Angle Formulas", "difficulty": "hard", "style": "standard", "paper": "G11-S3", "q": "Which of these is a correct form of the double angle formula for cos(2x)?", "options": ["cos(2x) = 2cosx", "cos(2x) = 1 − 2sin²x", "cos(2x) = sin²x − cos²x", "cos(2x) = 2sinxcosx"], "answer": 1, "exp": "One correct form of the double angle formula is cos(2x) = 1 − 2sin²x (other equivalent forms include cos²x−sin²x and 2cos²x−1).", "hint": "Recall the several equivalent versions of this double angle identity — this is one of them."}, {"id": "srs113005", "state": "AU", "section": "sr_specialist", "grade": "11", "topic": "Trigonometry — Double Angle Formulas", "difficulty": "hard", "style": "standard", "paper": "G11-S3", "q": "Using cos(2x) = 1 − 2sin²x, find cos(2x) given sinx = 1/2 (where x = 30°).", "options": ["0", "1/2", "3/4", "1"], "answer": 1, "exp": "Step 1: cos(2x) = 1 − 2×(1/2)² = 1 − 2×(1/4). Step 2: 1 − 1/2 = 1/2.", "hint": "Substitute sinx=1/2 into the double angle formula and simplify."}, {"id": "srs113006", "state": "AU", "section": "sr_specialist", "grade": "11", "topic": "Trigonometry — Pythagorean Identity", "difficulty": "hard", "style": "standard", "paper": "G11-S3", "q": "Which identity correctly states the Pythagorean identity relating sine and cosine?", "options": ["sinx + cosx = 1", "sin²x + cos²x = 1", "sinx × cosx = 1", "sin²x − cos²x = 1"], "answer": 1, "exp": "The fundamental Pythagorean identity is sin²x + cos²x = 1, true for all values of x.", "hint": "Remember this identity comes directly from applying Pythagoras' theorem to the unit circle."}, {"id": "srs113007", "state": "AU", "section": "sr_specialist", "grade": "11", "topic": "Trigonometry — Pythagorean Identity", "difficulty": "hard", "style": "standard", "paper": "G11-S3", "q": "Using the Pythagorean identity, if sinx = 3/5 (with x in the first quadrant), find cosx.", "options": ["3/5", "4/5", "-4/5", "16/25"], "answer": 1, "exp": "Step 1: sin²x+cos²x=1, so cos²x=1−(3/5)²=1−9/25=16/25. Step 2: cosx=4/5 (taking the positive root, since x is in the first quadrant).", "hint": "Use the Pythagorean identity to find cos²x, then take the appropriate square root based on the given quadrant."}, {"id": "srs113008", "state": "AU", "section": "sr_specialist", "grade": "11", "topic": "Proof — Mathematical Induction", "difficulty": "hard", "style": "standard", "paper": "G11-S3", "q": "Which best describes a 'proof by mathematical induction'?", "options": ["a proof technique that only works for a single specific case", "a proof technique that establishes a base case, then shows that if the statement holds for some value k, it must also hold for k+1, proving it for all relevant integers", "a proof technique that relies entirely on numerical approximation", "a proof technique used only in geometry, never algebra"], "answer": 1, "exp": "Mathematical induction establishes a base case (often n=1), then shows that IF the statement holds for some value k, it must ALSO hold for k+1 — together, these two steps prove the statement for all relevant integers.", "hint": "Think about a two-step process: establishing a starting point, then showing each step logically follows from the previous one, like a chain of dominoes."}, {"id": "srs113009", "state": "AU", "section": "sr_specialist", "grade": "11", "topic": "Proof — Mathematical Induction", "difficulty": "hard", "style": "standard", "paper": "G11-S3", "q": "In a proof by induction for the formula 1+2+3+...+n = n(n+1)/2, what is the first step (the 'base case')?", "options": ["assuming the formula is true for some unspecified value of n", "proving the formula holds for the SMALLEST relevant value of n (often n=1)", "proving the formula holds for all values of n simultaneously", "skipping directly to the inductive step"], "answer": 1, "exp": "The base case involves proving the formula holds for the smallest relevant value of n (typically n=1), establishing a starting point for the inductive argument.", "hint": "Think about establishing the very first 'domino' in the chain, before showing how each domino knocks over the next."}, {"id": "srs113010", "state": "AU", "section": "sr_specialist", "grade": "11", "topic": "Proof — Mathematical Induction", "difficulty": "hard", "style": "standard", "paper": "G11-S3", "q": "Using the formula 1+2+...+n = n(n+1)/2, verify that this formula gives the correct sum for n=5.", "options": ["10", "12", "15", "20"], "answer": 2, "exp": "Step 1: Using the formula: 5(5+1)/2 = 5×6/2 = 15. Step 2: This matches the direct sum 1+2+3+4+5=15, confirming the formula for this case.", "hint": "Substitute n=5 into the formula and compare with the direct sum."}, {"id": "srs113011", "state": "AU", "section": "sr_specialist", "grade": "11", "topic": "Proof — Proof by Contradiction", "difficulty": "hard", "style": "standard", "paper": "G11-S3", "q": "Which best describes a 'proof by contradiction'?", "options": ["a proof that assumes the statement is true and derives a contradiction", "a proof that assumes the OPPOSITE of what you want to prove, and shows this assumption leads to a logical contradiction, thereby proving the original statement must be true", "a proof technique that can never actually establish anything true", "a synonym for proof by induction"], "answer": 1, "exp": "A proof by contradiction assumes the opposite of what you're trying to prove, then shows this assumption leads to a logical contradiction (an impossible or false conclusion), which means the original statement must actually be true.", "hint": "Think about assuming the OPPOSITE of what you believe is true, and showing that this leads to something impossible."}, {"id": "srs113012", "state": "AU", "section": "sr_specialist", "grade": "11", "topic": "Proof — Proof by Contradiction", "difficulty": "hard", "style": "standard", "paper": "G11-S3", "q": "The classic proof that √2 is irrational uses proof by contradiction. What is assumed at the start of this proof?", "options": ["that √2 is definitely irrational", "that √2 can be expressed as a fraction a/b in simplest form, where a and b are integers with no common factors", "that √2 equals exactly 1.414", "that all square roots are rational"], "answer": 1, "exp": "This classic proof begins by assuming the opposite of what we want to prove: that √2 CAN be expressed as a fraction a/b in simplest form (a rational number), then derives a contradiction from this assumption.", "hint": "Remember that proof by contradiction starts by assuming the OPPOSITE of the statement you ultimately want to prove."}, {"id": "srs113013", "state": "AU", "section": "sr_specialist", "grade": "11", "topic": "Proof — Counterexamples", "difficulty": "hard", "style": "standard", "paper": "G11-S3", "q": "Which best describes a 'counterexample' in mathematical proof?", "options": ["a proof that confirms a general statement is true", "a single specific case that disproves a general statement, showing it is false", "a synonym for a base case in induction", "a proof technique that only applies to equations, not inequalities"], "answer": 1, "exp": "A counterexample is a single specific case that disproves a general statement — finding just one counterexample is enough to show a general claim is false.", "hint": "Think about how just ONE exception can be enough to disprove a general 'always true' claim."}, {"id": "srs113014", "state": "AU", "section": "sr_specialist", "grade": "11", "topic": "Proof — Counterexamples", "difficulty": "hard", "style": "standard", "paper": "G11-S3", "q": "A student claims 'all prime numbers are odd'. Which number serves as a counterexample to this claim?", "options": ["3", "4", "2", "9"], "answer": 2, "exp": "The number 2 is a prime number that is also even, directly disproving the claim that all prime numbers are odd.", "hint": "Think about the one even number that is also prime."}, {"id": "srs113015", "state": "AU", "section": "sr_specialist", "grade": "11", "topic": "Trigonometry — Tangent Identity", "difficulty": "hard", "style": "standard", "paper": "G11-S3", "q": "Using the formula tan(x) = sin(x)/cos(x), find tanx given sinx = 3/5 and cosx = 4/5.", "options": ["3/4", "4/3", "3/5", "4/5"], "answer": 0, "exp": "tanx = sinx/cosx = (3/5)/(4/5) = 3/4.", "hint": "Divide sinx by cosx directly, using the given values."}, {"id": "srs113016", "state": "AU", "section": "sr_specialist", "grade": "11", "topic": "Trigonometry — Tangent Identity", "difficulty": "hard", "style": "standard", "paper": "G11-S3", "q": "Which identity correctly relates tanx to sinx and cosx?", "options": ["tanx = sinx + cosx", "tanx = sinx/cosx", "tanx = cosx/sinx", "tanx = sinx × cosx"], "answer": 1, "exp": "By definition, tanx = sinx/cosx.", "hint": "Remember the fundamental definition of tangent in terms of sine and cosine."}, {"id": "srs113017", "state": "AU", "section": "sr_specialist", "grade": "11", "topic": "Trigonometry — Double Angle Formulas", "difficulty": "hard", "style": "standard", "paper": "G11-S3", "q": "Using the double angle formula tan(2x) = 2tanx/(1−tan²x), find tan(2x) given tanx = 1.", "options": ["0", "1", "2", "undefined"], "answer": 3, "exp": "Step 1: tan(2x) = 2(1)/(1−1²) = 2/0. Step 2: Division by zero means tan(2x) is undefined at this value (since 2x=90°, where tangent is undefined).", "hint": "Be careful — substituting tanx=1 creates a zero denominator, which has a specific mathematical meaning."}, {"id": "srs113018", "state": "AU", "section": "sr_specialist", "grade": "11", "topic": "Proof — Concepts", "difficulty": "hard", "style": "standard", "paper": "G11-S3", "q": "Which best describes why mathematical proof is considered more rigorous than checking many numerical examples?", "options": ["checking many examples is always sufficient to prove a general statement true", "numerical examples, no matter how many, cannot guarantee a statement holds for ALL cases, while a valid logical proof establishes the result for every possible case", "mathematical proof and numerical checking are exactly equivalent in rigour", "numerical checking is always more reliable than formal proof"], "answer": 1, "exp": "Numerical examples, no matter how many are checked, cannot guarantee a general statement holds for every possible case (there might always be an untested exception), while a valid logical proof establishes the result for ALL cases simultaneously.", "hint": "Think about whether checking even a thousand examples could ever truly guarantee something is true for every possible case, including ones not yet tested."}, {"id": "srs113019", "state": "AU", "section": "sr_specialist", "grade": "11", "topic": "Trigonometry — Compound Angle Formulas", "difficulty": "hard", "style": "standard", "paper": "G11-S3", "q": "Using compound angle formulas, simplify cos(x)cos(y) − sin(x)sin(y).", "options": ["cos(x+y)", "cos(x−y)", "sin(x+y)", "sin(x−y)"], "answer": 0, "exp": "This expression matches the compound angle formula for cos(x+y) = cosxcosy − sinxsiny exactly.", "hint": "Compare this expression directly to the standard compound angle formula for cosine of a sum."}, {"id": "srs113020", "state": "AU", "section": "sr_specialist", "grade": "11", "topic": "Trigonometry — Compound Angle Formulas", "difficulty": "hard", "style": "standard", "paper": "G11-S3", "q": "Using compound angle formulas, simplify sin(x)cos(y) − cos(x)sin(y).", "options": ["sin(x+y)", "sin(x−y)", "cos(x+y)", "cos(x−y)"], "answer": 1, "exp": "This expression matches the compound angle formula for sin(x−y) = sinxcosy − cosxsiny exactly.", "hint": "Compare this expression directly to the standard compound angle formula for sine of a difference."}, {"id": "srs113021", "state": "AU", "section": "sr_specialist", "grade": "11", "topic": "Proof — Direct Proof", "difficulty": "hard", "style": "standard", "paper": "G11-S3", "q": "Which best describes the structure of a direct mathematical proof?", "options": ["assuming the conclusion is false and deriving a contradiction", "starting from known facts or assumptions, and using logical steps to directly arrive at the desired conclusion", "testing many specific numerical examples until confident", "a proof technique that can only be used in geometry"], "answer": 1, "exp": "A direct proof starts from known facts, definitions, or assumptions, and uses a sequence of logical steps to directly arrive at the desired conclusion, without assuming the opposite or relying solely on examples.", "hint": "Think about the most straightforward proof structure: starting from what you know, and reasoning step by step toward what you want to show."}, {"id": "srs113022", "state": "AU", "section": "sr_specialist", "grade": "11", "topic": "Proof — Direct Proof", "difficulty": "hard", "style": "standard", "paper": "G11-S3", "q": "Prove or disprove: 'the sum of any two even numbers is always even.' Using a direct proof with even numbers represented as 2m and 2n (where m, n are integers), what is their sum?", "options": ["2m + 2n = 2(m+n), which is even since (m+n) is an integer", "2m + 2n = 4mn, which is always even", "2m + 2n cannot be simplified further", "this claim is false, with no possible proof"], "answer": 0, "exp": "Representing two even numbers as 2m and 2n, their sum is 2m+2n=2(m+n), which is clearly even, since it is 2 multiplied by an integer (m+n) — this directly proves the original claim.", "hint": "Add the two algebraic representations of even numbers together and factor out the common term."}, {"id": "srs113023", "state": "AU", "section": "sr_specialist", "grade": "11", "topic": "Proof — Mathematical Induction", "difficulty": "hard", "style": "standard", "paper": "G11-S3", "q": "In the inductive step of a proof by induction, what is typically assumed, and what must then be shown?", "options": ["nothing is assumed; the inductive step proves the statement for all n simultaneously", "it is assumed the statement holds for n=k (the 'inductive hypothesis'), and it must be shown that this implies the statement also holds for n=k+1", "the inductive step only needs to check n=1", "the inductive step replaces the need for a base case entirely"], "answer": 1, "exp": "In the inductive step, you assume the statement holds for some value n=k (called the inductive hypothesis), and then show that this assumption logically implies the statement must also hold for n=k+1.", "hint": "Think about assuming one specific 'domino' falls, then showing this necessarily knocks over the next one in the chain."}, {"id": "srs113024", "state": "AU", "section": "sr_specialist", "grade": "11", "topic": "Proof — Mathematical Induction", "difficulty": "hard", "style": "standard", "paper": "G11-S3", "q": "Which best describes why both the base case AND the inductive step are necessary for a complete proof by induction?", "options": ["only the base case is actually necessary", "without the base case, there's no starting point; without the inductive step, there's no way to extend the result beyond the base case to all other values", "only the inductive step is actually necessary", "both steps are optional and can be skipped for simple statements"], "answer": 1, "exp": "Without the base case, there's no verified starting point for the chain of implications; without the inductive step, there's no logical mechanism to extend the result from the base case to all the other relevant values — both are essential for a complete, valid proof.", "hint": "Think about why a chain of dominoes needs BOTH an initial push AND a guarantee that each domino will knock over the next one."}, {"id": "srs113025", "state": "AU", "section": "sr_specialist", "grade": "11", "topic": "Trigonometry — Pythagorean Identity", "difficulty": "hard", "style": "standard", "paper": "G11-S3", "q": "Using the Pythagorean identity, if cosx = -7/25 (with x in the second quadrant, where sine is positive), find sinx.", "options": ["7/25", "24/25", "-24/25", "18/25"], "answer": 1, "exp": "Step 1: sin²x = 1−cos²x = 1−(7/25)² = 1−49/625 = 576/625. Step 2: sinx = 24/25 (taking the positive root, since x is in the second quadrant where sine is positive).", "hint": "Use the Pythagorean identity to find sin²x, then take the appropriate sign based on the given quadrant."}, {"id": "srs114001", "state": "AU", "section": "sr_specialist", "grade": "11", "topic": "Combinatorics — Factorials", "difficulty": "hard", "style": "standard", "paper": "G11-S4", "q": "Evaluate: 5! (5 factorial)", "options": ["20", "60", "120", "720"], "answer": 2, "exp": "5! = 5×4×3×2×1 = 120.", "hint": "Multiply all positive integers from 1 up to 5."}, {"id": "srs114002", "state": "AU", "section": "sr_specialist", "grade": "11", "topic": "Combinatorics — Permutations", "difficulty": "hard", "style": "standard", "paper": "G11-S4", "q": "How many ways can 6 distinct books be arranged in a row on a shelf?", "options": ["36", "120", "360", "720"], "answer": 3, "exp": "The number of ways to arrange 6 distinct objects in a row is 6! = 720.", "hint": "Use the factorial formula for arranging a full set of distinct objects."}, {"id": "srs114003", "state": "AU", "section": "sr_specialist", "grade": "11", "topic": "Combinatorics — Permutations", "difficulty": "hard", "style": "standard", "paper": "G11-S4", "q": "How many ways can you choose and arrange 3 people from a group of 7, for first, second, and third place in a race? (Using the permutation formula P(n,r).)", "options": ["35", "210", "343", "5040"], "answer": 1, "exp": "Step 1: P(7,3) = 7!/(7-3)! = 7×6×5 = 210.", "hint": "Use the permutation formula, since the order (1st, 2nd, 3rd place) matters here."}, {"id": "srs114004", "state": "AU", "section": "sr_specialist", "grade": "11", "topic": "Combinatorics — Combinations", "difficulty": "hard", "style": "standard", "paper": "G11-S4", "q": "How many ways can you choose a committee of 4 people from a group of 10, where the order of selection doesn't matter? (Using the combination formula C(n,r).)", "options": ["40", "210", "5040", "10000"], "answer": 1, "exp": "Step 1: C(10,4) = 10!/(4!×6!) = 210.", "hint": "Use the combination formula, since the order of selection doesn't matter for a committee."}, {"id": "srs114005", "state": "AU", "section": "sr_specialist", "grade": "11", "topic": "Combinatorics — Concepts", "difficulty": "hard", "style": "standard", "paper": "G11-S4", "q": "Which best describes the key difference between a permutation and a combination?", "options": ["they are exactly the same thing, just with different names", "a permutation considers the order of selection important, while a combination does not", "combinations always result in a larger number than permutations for the same n and r", "permutations only apply to letters, while combinations only apply to numbers"], "answer": 1, "exp": "A permutation considers the order of selection important (e.g. 1st, 2nd, 3rd place), while a combination does not (e.g. simply selecting a group, with no ranking).", "hint": "Think about whether arranging the same items in a different order would count as a 'different' outcome."}, {"id": "srs114006", "state": "AU", "section": "sr_specialist", "grade": "11", "topic": "Combinatorics — Combinations", "difficulty": "hard", "style": "standard", "paper": "G11-S4", "q": "How many ways can a committee of 3 be chosen from a group of 5 people?", "options": ["10", "15", "20", "60"], "answer": 0, "exp": "C(5,3) = 5!/(3!×2!) = 10.", "hint": "Use the combination formula, since the order of selection doesn't matter."}, {"id": "srs114007", "state": "AU", "section": "sr_specialist", "grade": "11", "topic": "Combinatorics — Permutations with Repetition", "difficulty": "hard", "style": "standard", "paper": "G11-S4", "q": "How many distinct ways can the letters of the word 'MISSISSIPPI' be arranged, accounting for repeated letters? (M=1, I=4, S=4, P=2, total 11 letters)", "options": ["39,916,800", "34,650", "11,880", "1,663,200"], "answer": 1, "exp": "Step 1: Total arrangements if all letters were distinct: 11!. Step 2: Divide by the factorial of each repeated letter's count: 11!/(4!×4!×2!×1!) = 34,650.", "hint": "Divide the total factorial by the factorial of each letter's repetition count, to account for identical letters."}, {"id": "srs114008", "state": "AU", "section": "sr_specialist", "grade": "11", "topic": "Combinatorics — Permutations with Repetition", "difficulty": "hard", "style": "standard", "paper": "G11-S4", "q": "Which formula correctly accounts for repeated items when calculating distinct arrangements of a set of objects?", "options": ["n! (no adjustment needed for repeated items)", "n!/(r₁!×r₂!×...×rₖ!), dividing by the factorial of each repeated item's count", "n!/r!, treating all repeats as a single group", "n! × r!, multiplying by the repetition factor"], "answer": 1, "exp": "When some items are repeated, the formula divides the total arrangements (n!) by the factorial of each repeated item's count, to avoid overcounting indistinguishable arrangements.", "hint": "Think about why arrangements that swap two identical letters shouldn't be counted as genuinely 'different'."}, {"id": "srs114009", "state": "AU", "section": "sr_specialist", "grade": "11", "topic": "Combinatorics — Pigeonhole Principle", "difficulty": "hard", "style": "standard", "paper": "G11-S4", "q": "What is the 'pigeonhole principle', in simple terms?", "options": ["if n items are placed into n containers, each container must contain exactly one item", "if more items are placed into containers than there are containers, at least one container must contain more than one item", "a principle that only applies to actual pigeons and holes, not general mathematics", "a principle stating that probability is always evenly distributed"], "answer": 1, "exp": "The pigeonhole principle states that if more items are placed into containers than there are containers available, at least one container must contain more than one item.", "hint": "Think about trying to fit more pigeons than available holes — at least one hole must end up with more than one pigeon."}, {"id": "srs114010", "state": "AU", "section": "sr_specialist", "grade": "11", "topic": "Combinatorics — Pigeonhole Principle", "difficulty": "hard", "style": "standard", "paper": "G11-S4", "q": "Using the pigeonhole principle, if 13 people are in a room, what is the minimum number of people guaranteed to share the same birth MONTH (12 months total)?", "options": ["1", "2", "12", "13"], "answer": 1, "exp": "Since there are 13 people but only 12 possible birth months, by the pigeonhole principle, at least 2 people must share the same birth month.", "hint": "Compare the number of people to the number of available 'containers' (months) to apply the pigeonhole principle."}, {"id": "srs114011", "state": "AU", "section": "sr_specialist", "grade": "11", "topic": "Combinatorics — Circular Permutations", "difficulty": "hard", "style": "standard", "paper": "G11-S4", "q": "How many ways can 5 distinct people be arranged in a circle (where rotations are considered the same arrangement)?", "options": ["24", "60", "120", "720"], "answer": 0, "exp": "For circular arrangements where rotations are considered identical, the formula is (n-1)! rather than n!. For 5 people: (5-1)! = 4! = 24.", "hint": "Remember that circular arrangements use (n-1)! instead of n!, since rotating the whole circle doesn't create a genuinely new arrangement."}, {"id": "srs114012", "state": "AU", "section": "sr_specialist", "grade": "11", "topic": "Combinatorics — Combinations", "difficulty": "hard", "style": "standard", "paper": "G11-S4", "q": "Evaluate C(6,2), the number of ways to choose 2 items from 6.", "options": ["12", "15", "30", "36"], "answer": 1, "exp": "C(6,2) = 6!/(2!×4!) = 15.", "hint": "Use the combination formula for choosing 2 items from a set of 6."}, {"id": "srs114013", "state": "AU", "section": "sr_specialist", "grade": "11", "topic": "Combinatorics — Combinations", "difficulty": "hard", "style": "standard", "paper": "G11-S4", "q": "What is the value of C(n,0) for any positive integer n?", "options": ["0", "1", "n", "n!"], "answer": 1, "exp": "C(n,0)=1 for any n, since there is exactly one way to choose nothing from a set (the empty selection).", "hint": "Think about how many ways there are to select NONE of the items from any set."}, {"id": "srs114014", "state": "AU", "section": "sr_specialist", "grade": "11", "topic": "Combinatorics — Combinations", "difficulty": "hard", "style": "standard", "paper": "G11-S4", "q": "What is the value of C(n,n) for any positive integer n?", "options": ["0", "1", "n", "n!"], "answer": 1, "exp": "C(n,n)=1 for any n, since there is exactly one way to choose ALL of the items from a set of n.", "hint": "Think about how many ways there are to select EVERY item from a set."}, {"id": "srs114015", "state": "AU", "section": "sr_specialist", "grade": "11", "topic": "Combinatorics — Multiplication Principle", "difficulty": "hard", "style": "standard", "paper": "G11-S4", "q": "A multiple-choice test has 5 questions, each with 4 possible answers. Using the multiplication principle, how many different ways could a student answer all 5 questions (regardless of correctness)?", "options": ["20", "256", "1024", "3125"], "answer": 2, "exp": "Step 1: Each question has 4 independent choices. Step 2: Using the multiplication principle: 4×4×4×4×4 = 4⁵ = 1024.", "hint": "Multiply the number of choices for each question together, since each question's answer is independent."}, {"id": "srs114016", "state": "AU", "section": "sr_specialist", "grade": "11", "topic": "Combinatorics — Multiplication Principle", "difficulty": "hard", "style": "standard", "paper": "G11-S4", "q": "Which best describes the 'multiplication principle' in combinatorics?", "options": ["if there are m ways to do one task and n ways to do another independent task, there are m+n ways to do both", "if there are m ways to do one task and n ways to do another independent task, there are m×n ways to do both, in sequence", "the multiplication principle only applies to exactly two tasks", "this principle has no real practical application"], "answer": 1, "exp": "The multiplication principle states that if there are m ways to do one task and n ways to do another independent task, there are m×n ways to perform both tasks in sequence.", "hint": "Think about combining independent choices — multiplying (not adding) the number of options for each step."}, {"id": "srs114017", "state": "AU", "section": "sr_specialist", "grade": "11", "topic": "Combinatorics — Multiplication Principle", "difficulty": "hard", "style": "standard", "paper": "G11-S4", "q": "A restaurant offers 3 starters, 5 mains, and 2 desserts. Using the multiplication principle, how many different 3-course meals (one from each category) are possible?", "options": ["10", "15", "30", "32"], "answer": 2, "exp": "Using the multiplication principle: 3×5×2 = 30 different possible meal combinations.", "hint": "Multiply the number of choices in each category together."}, {"id": "srs114018", "state": "AU", "section": "sr_specialist", "grade": "11", "topic": "Combinatorics — Permutations", "difficulty": "hard", "style": "standard", "paper": "G11-S4", "q": "How many ways can a President and a Vice President be selected from a group of 8 people, where these are two distinct roles?", "options": ["28", "56", "64", "336"], "answer": 1, "exp": "Step 1: Since the two roles are distinct, use permutations: P(8,2) = 8×7 = 56.", "hint": "Since these are two distinct roles, order matters here — use the permutation formula."}, {"id": "srs114019", "state": "AU", "section": "sr_specialist", "grade": "11", "topic": "Combinatorics — Pigeonhole Principle", "difficulty": "hard", "style": "standard", "paper": "G11-S4", "q": "Using the pigeonhole principle, if you have 10 different pairs of socks (20 individual socks) all mixed together in a drawer with no light, what is the minimum number of socks you must pull out to guarantee at least one matching pair?", "options": ["2", "3", "10", "11"], "answer": 3, "exp": "In the worst case, you could pull out one sock from each of the 10 different pairs (10 socks, all different) before being forced to pull an 11th sock, which must match one already pulled — so 11 socks guarantees a matching pair.", "hint": "Think about the worst-case scenario: pulling out one of EVERY different pair before being forced into a repeat."}, {"id": "srs114020", "state": "AU", "section": "sr_specialist", "grade": "11", "topic": "Combinatorics — Multiplication Principle", "difficulty": "hard", "style": "standard", "paper": "G11-S4", "q": "How many different 4-digit codes can be created using the digits 0-9, if repetition of digits is allowed?", "options": ["210", "5040", "10000", "40320"], "answer": 2, "exp": "Since each of the 4 positions can independently be any of the 10 digits (0-9), with repetition allowed: 10×10×10×10 = 10,000.", "hint": "Since repetition is allowed, each position has the full 10 options available, independent of the others."}, {"id": "srs114021", "state": "AU", "section": "sr_specialist", "grade": "11", "topic": "Combinatorics — Permutations", "difficulty": "hard", "style": "standard", "paper": "G11-S4", "q": "How many different 4-digit codes can be created using the digits 0-9, if NO digit can be repeated?", "options": ["210", "5040", "10000", "40320"], "answer": 1, "exp": "Step 1: Since no repetition is allowed, use permutations: P(10,4) = 10×9×8×7 = 5040.", "hint": "Since no repetition is allowed, the number of available choices decreases by one for each subsequent position."}, {"id": "srs114022", "state": "AU", "section": "sr_specialist", "grade": "11", "topic": "Combinatorics — Concepts", "difficulty": "hard", "style": "standard", "paper": "G11-S4", "q": "Which best describes when to use combinations rather than permutations, when selecting a subset from a larger group?", "options": ["use combinations whenever the order of selection matters", "use combinations when the order of selection does NOT matter (e.g. choosing a team, rather than ranking members)", "combinations and permutations always give the same numerical result", "combinations should always be used, regardless of context"], "answer": 1, "exp": "Combinations should be used when the order of selection does NOT matter, such as choosing a team or committee, where simply being selected matters, not the order in which members were chosen.", "hint": "Think about whether rearranging the same selected group would actually create a meaningfully 'different' outcome."}, {"id": "srs114023", "state": "AU", "section": "sr_specialist", "grade": "11", "topic": "Combinatorics — Pigeonhole Principle", "difficulty": "hard", "style": "standard", "paper": "G11-S4", "q": "Using the pigeonhole principle, prove that among any 5 integers, at least two must have the same remainder when divided by 4 (since there are only 4 possible remainders: 0, 1, 2, 3).", "options": ["this cannot be proven using the pigeonhole principle", "since there are 5 integers (items) but only 4 possible remainders (containers), at least two integers must share the same remainder", "this is only true for even integers", "the pigeonhole principle only applies to physical objects, not abstract numbers like remainders"], "answer": 1, "exp": "Since there are 5 integers (items) being distributed among only 4 possible remainder categories (containers: 0, 1, 2, or 3), the pigeonhole principle guarantees that at least two integers must share the same remainder.", "hint": "Think about the integers as 'items' and the possible remainders as 'containers', then apply the pigeonhole principle directly."}, {"id": "srs114024", "state": "AU", "section": "sr_specialist", "grade": "11", "topic": "Combinatorics — Applications", "difficulty": "hard", "style": "standard", "paper": "G11-S4", "q": "Which best describes why combinatorics (the study of counting) is foundational to probability theory?", "options": ["combinatorics and probability are entirely unrelated fields", "calculating probabilities often requires counting the number of favourable outcomes and the total number of possible outcomes, which is exactly what combinatorics provides tools for", "probability never actually requires any counting", "combinatorics can only be used for games of chance, not real probability calculations"], "answer": 1, "exp": "Calculating probabilities often requires counting both the number of favourable outcomes and the total number of possible outcomes — combinatorial tools like permutations and combinations provide systematic ways to perform this counting accurately.", "hint": "Think about how calculating probability (favourable outcomes ÷ total outcomes) fundamentally relies on being able to count both quantities accurately."}, {"id": "srs114025", "state": "AU", "section": "sr_specialist", "grade": "11", "topic": "Combinatorics — Combinations", "difficulty": "hard", "style": "standard", "paper": "G11-S4", "q": "How many ways can a hand of 5 cards be dealt from a standard 52-card deck, where the order the cards are dealt in doesn't matter?", "options": ["311,875,200", "2,598,960", "132,600", "1,326"], "answer": 1, "exp": "Since the order of the cards in a hand doesn't matter, use the combination formula: C(52,5) = 52!/(5!×47!) = 2,598,960.", "hint": "Since order doesn't matter for a hand of cards, use the combination formula rather than permutations."}, {"id": "srs121001", "state": "AU", "section": "sr_specialist", "grade": "12", "topic": "Complex Numbers — Polar Form", "difficulty": "hard", "style": "standard", "paper": "G12-S1", "q": "Express z = 1 + i in polar form (modulus-argument form), giving the modulus and argument.", "options": ["r=√2, θ=45°", "r=2, θ=45°", "r=√2, θ=90°", "r=1, θ=45°"], "answer": 0, "exp": "Step 1: Modulus r = √(1²+1²) = √2. Step 2: Argument θ = tan⁻¹(1/1) = 45°.", "hint": "Calculate the modulus using Pythagoras' theorem, and the argument using the inverse tangent of the imaginary part over the real part."}, {"id": "srs121002", "state": "AU", "section": "sr_specialist", "grade": "12", "topic": "Complex Numbers — Polar Form", "difficulty": "hard", "style": "standard", "paper": "G12-S1", "q": "Express z = √3 + i in polar form, giving the modulus and argument.", "options": ["r=2, θ=30°", "r=2, θ=60°", "r=4, θ=30°", "r=√3, θ=45°"], "answer": 0, "exp": "Step 1: Modulus r = √((√3)²+1²) = √(3+1) = 2. Step 2: Argument θ = tan⁻¹(1/√3) = 30°.", "hint": "Calculate the modulus using Pythagoras' theorem, and the argument using the inverse tangent ratio."}, {"id": "srs121003", "state": "AU", "section": "sr_specialist", "grade": "12", "topic": "Complex Numbers — De Moivre's Theorem", "difficulty": "hard", "style": "standard", "paper": "G12-S1", "q": "Which best describes De Moivre's theorem?", "options": ["(cosθ + isinθ)ⁿ = cos(nθ) + isin(nθ), for any integer n", "(cosθ + isinθ)ⁿ = n(cosθ + isinθ)", "(cosθ + isinθ)ⁿ = cosθⁿ + isinθⁿ", "De Moivre's theorem only applies when n=2"], "answer": 0, "exp": "De Moivre's theorem states that (cosθ+isinθ)ⁿ = cos(nθ)+isin(nθ), for any integer n, providing a powerful way to raise complex numbers in polar form to a power.", "hint": "Remember that the exponent n is applied directly to the ANGLE, not to each trigonometric function separately."}, {"id": "srs121004", "state": "AU", "section": "sr_specialist", "grade": "12", "topic": "Complex Numbers — De Moivre's Theorem", "difficulty": "hard", "style": "standard", "paper": "G12-S1", "q": "Using De Moivre's theorem, simplify (cos30° + isin30°)³.", "options": ["cos90° + isin90°, which equals i", "cos30° + isin30°", "cos90° + isin90°, which equals -1", "cos10° + isin10°"], "answer": 0, "exp": "Step 1: By De Moivre's theorem: (cos30°+isin30°)³ = cos(3×30°)+isin(3×30°) = cos90°+isin90°. Step 2: This equals 0+i(1) = i.", "hint": "Multiply the angle by the exponent, then evaluate the resulting trigonometric expression."}, {"id": "srs121005", "state": "AU", "section": "sr_specialist", "grade": "12", "topic": "Complex Numbers — De Moivre's Theorem", "difficulty": "hard", "style": "standard", "paper": "G12-S1", "q": "Using De Moivre's theorem (or direct expansion), evaluate (1 + i)⁴.", "options": ["-4", "4", "-4i", "4i"], "answer": 0, "exp": "Step 1: In polar form, 1+i has modulus √2 and argument 45°. Step 2: (1+i)⁴ = (√2)⁴(cos180°+isin180°) = 4×(-1+0i) = -4.", "hint": "Convert to polar form first, then apply De Moivre's theorem, raising the modulus to the 4th power and multiplying the angle by 4."}, {"id": "srs121006", "state": "AU", "section": "sr_specialist", "grade": "12", "topic": "Complex Numbers — Roots of Complex Numbers", "difficulty": "hard", "style": "standard", "paper": "G12-S1", "q": "Find all the cube roots of 1 (solutions to z³ = 1) over the complex numbers.", "options": ["z = 1 only", "z = 1, -1", "z = 1, -1/2 + (√3/2)i, -1/2 − (√3/2)i", "z = 1, i, -1"], "answer": 2, "exp": "The equation z³=1 has three solutions: the real root z=1, and two complex roots, -1/2 ± (√3/2)i, evenly spaced around the unit circle.", "hint": "Remember that an equation zⁿ=1 has exactly n solutions, evenly spaced around the unit circle in the complex plane."}, {"id": "srs121007", "state": "AU", "section": "sr_specialist", "grade": "12", "topic": "Complex Numbers — Roots of Complex Numbers", "difficulty": "hard", "style": "standard", "paper": "G12-S1", "q": "How many solutions does the equation zⁿ = 1 have, over the complex numbers, for a positive integer n?", "options": ["always exactly 1 solution", "always exactly 2 solutions", "exactly n solutions", "infinitely many solutions"], "answer": 2, "exp": "The equation zⁿ=1 always has exactly n solutions over the complex numbers, known as the 'nth roots of unity', evenly spaced around the unit circle.", "hint": "Think about how many distinct solutions a polynomial equation of degree n can have, according to the fundamental theorem of algebra."}, {"id": "srs121008", "state": "AU", "section": "sr_specialist", "grade": "12", "topic": "Complex Numbers — Multiplication in Polar Form", "difficulty": "hard", "style": "standard", "paper": "G12-S1", "q": "Two complex numbers in polar form are z₁ = 2(cos60° + isin60°) and z₂ = 3(cos30° + isin30°). Find |z₁ × z₂|.", "options": ["5", "6", "9", "36"], "answer": 1, "exp": "When multiplying complex numbers in polar form, the moduli multiply: |z₁×z₂| = |z₁|×|z₂| = 2×3 = 6.", "hint": "Remember that when multiplying complex numbers, you multiply their moduli together."}, {"id": "srs121009", "state": "AU", "section": "sr_specialist", "grade": "12", "topic": "Complex Numbers — Multiplication in Polar Form", "difficulty": "hard", "style": "standard", "paper": "G12-S1", "q": "Using the same z₁ and z₂ from the previous question, find the argument of z₁ × z₂.", "options": ["30°", "60°", "90°", "180°"], "answer": 2, "exp": "When multiplying complex numbers in polar form, the arguments add: arg(z₁×z₂) = arg(z₁)+arg(z₂) = 60°+30° = 90°.", "hint": "Remember that when multiplying complex numbers, you add their arguments together."}, {"id": "srs121010", "state": "AU", "section": "sr_specialist", "grade": "12", "topic": "Complex Numbers — Division in Polar Form", "difficulty": "hard", "style": "standard", "paper": "G12-S1", "q": "For division of complex numbers in polar form, z₁/z₂, which best describes the resulting modulus and argument?", "options": ["the moduli are added, and the arguments are multiplied", "the moduli are divided, and the arguments are subtracted", "the moduli are multiplied, and the arguments are added", "division is not possible for complex numbers in polar form"], "answer": 1, "exp": "When dividing complex numbers in polar form, the moduli are divided (|z₁|/|z₂|), and the arguments are subtracted (arg(z₁)−arg(z₂)).", "hint": "Remember that division is the inverse of multiplication, so the operations on modulus and argument should also be inverse operations."}, {"id": "srs121011", "state": "AU", "section": "sr_specialist", "grade": "12", "topic": "Complex Numbers — Division in Polar Form", "difficulty": "hard", "style": "standard", "paper": "G12-S1", "q": "Given z₁ = 8(cos120° + isin120°) and z₂ = 2(cos40° + isin40°), find z₁/z₂ in polar form.", "options": ["4(cos80° + isin80°)", "16(cos80° + isin80°)", "4(cos160° + isin160°)", "6(cos80° + isin80°)"], "answer": 0, "exp": "Step 1: Divide the moduli: 8÷2=4. Step 2: Subtract the arguments: 120°−40°=80°. Step 3: Result: 4(cos80°+isin80°).", "hint": "Divide the moduli and subtract the arguments to find the result in polar form."}, {"id": "srs121012", "state": "AU", "section": "sr_specialist", "grade": "12", "topic": "Complex Numbers — De Moivre's Theorem", "difficulty": "hard", "style": "standard", "paper": "G12-S1", "q": "Which best describes why De Moivre's theorem is particularly useful for finding powers and roots of complex numbers, compared to repeated direct multiplication?", "options": ["it provides no real advantage over direct multiplication", "it converts the often tedious process of repeated multiplication into a simpler calculation involving multiplying the angle and raising the modulus to a power", "De Moivre's theorem can only be used for squaring complex numbers", "direct multiplication is always faster than using De Moivre's theorem"], "answer": 1, "exp": "De Moivre's theorem converts the often tedious process of repeatedly multiplying a complex number by itself into a simpler calculation: raising the modulus to the required power, and multiplying the argument by the same power.", "hint": "Think about how much simpler it is to multiply an angle by a number, compared to multiplying out a complex expression repeatedly."}, {"id": "srs121013", "state": "AU", "section": "sr_specialist", "grade": "12", "topic": "Complex Numbers — Polar Form", "difficulty": "hard", "style": "standard", "paper": "G12-S1", "q": "Express the complex number z = -2 + 2i in polar form.", "options": ["r=2√2, θ=135°", "r=2√2, θ=45°", "r=4, θ=135°", "r=2, θ=135°"], "answer": 0, "exp": "Step 1: Modulus r = √((-2)²+2²) = √8 = 2√2. Step 2: Since the real part is negative and imaginary part is positive (second quadrant), and the reference angle is 45°, the argument is 180°−45°=135°.", "hint": "Calculate the modulus first, then carefully determine the correct quadrant for the argument, since both components have specific signs."}, {"id": "srs121014", "state": "AU", "section": "sr_specialist", "grade": "12", "topic": "Complex Numbers — Argand Diagrams", "difficulty": "hard", "style": "standard", "paper": "G12-S1", "q": "Which quadrant of the complex plane does the complex number z = -3 - 4i lie in?", "options": ["first quadrant", "second quadrant", "third quadrant", "fourth quadrant"], "answer": 2, "exp": "Since both the real part (-3) and imaginary part (-4) are negative, this complex number lies in the third quadrant.", "hint": "Think about the sign of each component, matching it to the corresponding quadrant on a standard coordinate plane."}, {"id": "srs121015", "state": "AU", "section": "sr_specialist", "grade": "12", "topic": "Complex Numbers — De Moivre's Theorem", "difficulty": "hard", "style": "standard", "paper": "G12-S1", "q": "Using De Moivre's theorem, find (cos45° + isin45°)⁸.", "options": ["cos360° + isin360°, which equals 1", "cos45° + isin45°", "cos8° + isin8°", "cos360° + isin360°, which equals -1"], "answer": 0, "exp": "Step 1: (cos45°+isin45°)⁸ = cos(8×45°)+isin(8×45°) = cos360°+isin360°. Step 2: This equals 1+0i = 1.", "hint": "Multiply the angle by the exponent, then evaluate the resulting trigonometric expression (remembering 360° brings you back to the start)."}, {"id": "srs121016", "state": "AU", "section": "sr_specialist", "grade": "12", "topic": "Complex Numbers — Geometric Interpretation", "difficulty": "hard", "style": "standard", "paper": "G12-S1", "q": "Which best describes the geometric effect of multiplying a complex number z by i?", "options": ["it reflects z across the real axis", "it rotates z by 90° anticlockwise around the origin, with no change in modulus", "it doubles the modulus of z", "it has no geometric effect at all"], "answer": 1, "exp": "Multiplying a complex number by i rotates it by exactly 90° anticlockwise around the origin in the complex plane, with no change to its modulus (since |i|=1).", "hint": "Think about the modulus and argument of i itself (modulus 1, argument 90°), and how multiplying by it would affect another complex number."}, {"id": "srs121017", "state": "AU", "section": "sr_specialist", "grade": "12", "topic": "Complex Numbers — Roots of Complex Numbers", "difficulty": "hard", "style": "standard", "paper": "G12-S1", "q": "Find the 4 distinct fourth roots of unity (solutions to z⁴ = 1).", "options": ["z = 1, -1 only (2 solutions)", "z = 1, i, -1, -i", "z = 1, 2i, -1, -2i", "z = 1 only"], "answer": 1, "exp": "The equation z⁴=1 has exactly 4 solutions, evenly spaced 90° apart around the unit circle: z = 1, i, -1, and -i.", "hint": "Remember that the n solutions to zⁿ=1 are evenly spaced around the unit circle — for n=4, this means every 90°."}, {"id": "srs121018", "state": "AU", "section": "sr_specialist", "grade": "12", "topic": "Complex Numbers — Roots of Complex Numbers", "difficulty": "hard", "style": "standard", "paper": "G12-S1", "q": "Which best describes why the nth roots of unity are evenly spaced around the unit circle in the complex plane?", "options": ["this is purely coincidental with no underlying mathematical reason", "since the roots all have a modulus of 1, and their arguments are evenly spaced by 360°/n (a consequence of De Moivre's theorem), they form a regular pattern around the circle", "the roots are randomly distributed, with no particular pattern", "only some roots of unity lie on the unit circle, not all of them"], "answer": 1, "exp": "Since all nth roots of unity have a modulus of exactly 1, and De Moivre's theorem shows their arguments must be evenly spaced by 360°/n to satisfy zⁿ=1, they form a perfectly regular, evenly-spaced pattern around the unit circle.", "hint": "Think about applying De Moivre's theorem in reverse — what set of angles, when multiplied by n, would all give a result equivalent to 0° (i.e. equal to 1)?"}, {"id": "srs121019", "state": "AU", "section": "sr_specialist", "grade": "12", "topic": "Complex Numbers — Polar to Cartesian Conversion", "difficulty": "hard", "style": "standard", "paper": "G12-S1", "q": "Express z = 4(cos180° + isin180°) in Cartesian (a + bi) form.", "options": ["4", "-4", "4i", "-4i"], "answer": 1, "exp": "Step 1: cos180°=-1, sin180°=0. Step 2: z = 4×(-1) + 4×0×i = -4.", "hint": "Substitute the known values of cos180° and sin180°, then simplify."}, {"id": "srs121020", "state": "AU", "section": "sr_specialist", "grade": "12", "topic": "Complex Numbers — Polar to Cartesian Conversion", "difficulty": "hard", "style": "standard", "paper": "G12-S1", "q": "Express z = 6(cos90° + isin90°) in Cartesian (a + bi) form.", "options": ["6", "-6", "6i", "-6i"], "answer": 2, "exp": "Step 1: cos90°=0, sin90°=1. Step 2: z = 6×0 + 6×1×i = 6i.", "hint": "Substitute the known values of cos90° and sin90°, then simplify."}, {"id": "srs121021", "state": "AU", "section": "sr_specialist", "grade": "12", "topic": "Complex Numbers — Polar Form", "difficulty": "hard", "style": "standard", "paper": "G12-S1", "q": "Which best describes how the polar form of a complex number relates to its position on an Argand diagram?", "options": ["polar form has no connection to the Argand diagram", "the modulus represents the distance from the origin, while the argument represents the angle measured anticlockwise from the positive real axis", "the modulus represents the angle, while the argument represents the distance from the origin", "polar form can only describe complex numbers with a positive real part"], "answer": 1, "exp": "In polar form, the modulus represents the distance of the complex number from the origin, while the argument represents the angle measured anticlockwise from the positive real axis to the line connecting the origin and the point.", "hint": "Think about how the modulus and argument together specify a point's exact position, similar to distance and direction."}, {"id": "srs121022", "state": "AU", "section": "sr_specialist", "grade": "12", "topic": "Complex Numbers — Polar Form", "difficulty": "hard", "style": "standard", "paper": "G12-S1", "q": "Given z = 5(cos200° + isin200°), what is an equivalent way to express the argument, using a value between -180° and 180°?", "options": ["200°", "-160°", "160°", "-200°"], "answer": 1, "exp": "Since 200° is more than 180°, subtract 360° to find an equivalent angle within the standard range: 200°−360° = -160°.", "hint": "Subtract 360° from the given angle to bring it within the standard range of -180° to 180°."}, {"id": "srs121023", "state": "AU", "section": "sr_specialist", "grade": "12", "topic": "Complex Numbers — Polar Form", "difficulty": "hard", "style": "standard", "paper": "G12-S1", "q": "Which best describes the principal argument of a complex number?", "options": ["the argument expressed as any positive angle, however large", "the unique argument value within the range -180° (exclusive) to 180° (inclusive), or equivalently 0° to 360°, depending on convention", "a synonym for the modulus", "an argument that can only be calculated for real numbers"], "answer": 1, "exp": "The principal argument is the unique argument value typically expressed within the range -180° (exclusive) to 180° (inclusive), providing one standard, unambiguous way to specify direction (since adding or subtracting full rotations of 360° gives an equivalent angle).", "hint": "Think about why a standard convention is needed, given that the same direction can be described by infinitely many equivalent angles (differing by full rotations)."}, {"id": "srs121024", "state": "AU", "section": "sr_specialist", "grade": "12", "topic": "Complex Numbers — Multiplication in Polar Form", "difficulty": "hard", "style": "standard", "paper": "G12-S1", "q": "Given z₁ = 2(cos50° + isin50°) and z₂ = 5(cos20° + isin20°), find z₁ × z₂ in polar form.", "options": ["10(cos70° + isin70°)", "7(cos70° + isin70°)", "10(cos30° + isin30°)", "7(cos1000° + isin1000°)"], "answer": 0, "exp": "Step 1: Multiply the moduli: 2×5=10. Step 2: Add the arguments: 50°+20°=70°. Step 3: Result: 10(cos70°+isin70°).", "hint": "Multiply the moduli together and add the arguments together."}, {"id": "srs121025", "state": "AU", "section": "sr_specialist", "grade": "12", "topic": "Complex Numbers — Polar Form", "difficulty": "hard", "style": "standard", "paper": "G12-S1", "q": "Find |z|, the modulus of z = -5 (a purely real negative number), expressed as a complex number.", "options": ["-5", "0", "5", "25"], "answer": 2, "exp": "The modulus of any complex number is always non-negative, representing distance from the origin: |−5| = 5.", "hint": "Remember that modulus represents a distance, which is always non-negative, regardless of the sign of the original number."}, {"id": "srs122001", "state": "AU", "section": "sr_specialist", "grade": "12", "topic": "Vectors — Vector Equations of Lines", "difficulty": "hard", "style": "standard", "paper": "G12-S2", "q": "A line has vector equation r(t) = (1,2,3) + t(2,-1,1). Find r(2).", "options": ["(3, 1, 4)", "(5, 0, 5)", "(5, 1, 5)", "(3, 0, 4)"], "answer": 1, "exp": "Step 1: r(2) = (1,2,3) + 2(2,-1,1) = (1,2,3)+(4,-2,2). Step 2: (1+4, 2-2, 3+2) = (5, 0, 5).", "hint": "Substitute t=2 into the vector equation and add the resulting components."}, {"id": "srs122002", "state": "AU", "section": "sr_specialist", "grade": "12", "topic": "Vectors — Vector Equations of Lines", "difficulty": "hard", "style": "standard", "paper": "G12-S2", "q": "Using the line r(t) = (1,2,3) + t(2,-1,1), does the point (5, 0, 5) lie on this line?", "options": ["yes, when t=2", "yes, when t=1", "no, this point is not on the line", "this cannot be determined"], "answer": 0, "exp": "From the previous calculation, r(2) = (5,0,5), confirming this point lies on the line at t=2.", "hint": "Check whether substituting some value of t into the vector equation produces exactly this point."}, {"id": "srs122003", "state": "AU", "section": "sr_specialist", "grade": "12", "topic": "Vectors — Vector Equations of Lines", "difficulty": "hard", "style": "standard", "paper": "G12-S2", "q": "Which best describes the general form of a vector equation of a line, r(t) = a + td?", "options": ["a represents the direction vector, and d represents a known point on the line", "a represents a known point on the line, and d represents the direction vector, with t as a scalar parameter", "both a and d must be points on the line", "t must always be a fixed constant, not a variable parameter"], "answer": 1, "exp": "In the equation r(t) = a + td, 'a' represents a known point on the line, 'd' represents the line's direction vector, and t is a variable scalar parameter that generates every point on the line as it varies.", "hint": "Think about which part of the equation gives you a FIXED starting point, and which part gives you the DIRECTION you move along."}, {"id": "srs122004", "state": "AU", "section": "sr_specialist", "grade": "12", "topic": "Vectors — Scalar Resolute", "difficulty": "hard", "style": "standard", "paper": "G12-S2", "q": "Find the scalar resolute (scalar projection) of u = (3, 4) onto v = (1, 0).", "options": ["3", "4", "5", "7"], "answer": 0, "exp": "Step 1: Scalar resolute = (u·v)/|v|. Step 2: u·v = (3×1)+(4×0) = 3. Step 3: |v|=1, so the scalar resolute is 3/1=3.", "hint": "Use the formula: (dot product of u and v) divided by the magnitude of v."}, {"id": "srs122005", "state": "AU", "section": "sr_specialist", "grade": "12", "topic": "Vectors — Vector Resolute", "difficulty": "hard", "style": "standard", "paper": "G12-S2", "q": "Find the vector resolute (vector projection) of u = (3, 4) onto v = (1, 0).", "options": ["(3, 0)", "(3, 4)", "(4, 0)", "(0, 4)"], "answer": 0, "exp": "Step 1: Vector resolute = [(u·v)/(v·v)]×v. Step 2: (u·v)=3, (v·v)=1, so the scalar factor is 3. Step 3: 3×(1,0) = (3, 0).", "hint": "Find the scalar factor first using the dot products, then multiply this by the vector v itself."}, {"id": "srs122006", "state": "AU", "section": "sr_specialist", "grade": "12", "topic": "Vectors — Vector Resolute", "difficulty": "hard", "style": "standard", "paper": "G12-S2", "q": "Which best describes the 'vector resolute' (vector projection) of u onto v, geometrically?", "options": ["the vector representing how much of u points in the direction of v", "a scalar value with no directional meaning", "the angle between u and v", "the cross product of u and v"], "answer": 0, "exp": "The vector resolute represents the vector component of u that points in the direction of v — geometrically, it's like the 'shadow' that u casts onto the line defined by v.", "hint": "Think about the 'shadow' one vector would cast onto the direction of another, if light shone perpendicular to that direction."}, {"id": "srs122007", "state": "AU", "section": "sr_specialist", "grade": "12", "topic": "Vectors — Cross Product", "difficulty": "hard", "style": "standard", "paper": "G12-S2", "q": "Given vectors a = (1,2,3) and b = (4,5,6), find the cross product a × b.", "options": ["(-3, 6, -3)", "(3, -6, 3)", "(4, 10, 18)", "(-3, -6, -3)"], "answer": 0, "exp": "Using the cross product formula: a×b = (a₂b₃−a₃b₂, a₃b₁−a₁b₃, a₁b₂−a₂b₁) = (2×6−3×5, 3×4−1×6, 1×5−2×4) = (12−15, 12−6, 5−8) = (-3, 6, -3).", "hint": "Use the standard cross product formula, carefully tracking each component."}, {"id": "srs122008", "state": "AU", "section": "sr_specialist", "grade": "12", "topic": "Vectors — Cross Product", "difficulty": "hard", "style": "standard", "paper": "G12-S2", "q": "Which best describes a key property of the cross product a × b, in 3D vectors?", "options": ["the result is always a scalar value", "the result is a vector perpendicular to both a and b", "the cross product is commutative, meaning a×b = b×a", "the cross product can only be calculated for 2D vectors"], "answer": 1, "exp": "A key property of the cross product is that the resulting vector is always perpendicular to both of the original vectors a and b (in 3D), which is why it's particularly useful for finding normal vectors to planes.", "hint": "Think about the special geometric direction that the resulting vector always points in, relative to the two original vectors."}, {"id": "srs122009", "state": "AU", "section": "sr_specialist", "grade": "12", "topic": "Vectors — Cross Product", "difficulty": "hard", "style": "standard", "paper": "G12-S2", "q": "Using a = (1,2,3) and b = (4,5,6), with a×b = (-3, 6, -3), find the magnitude |a×b|.", "options": ["3√2", "3√6", "6√3", "18"], "answer": 1, "exp": "Step 1: |a×b| = √((-3)²+6²+(-3)²). Step 2: √(9+36+9) = √54 = 3√6.", "hint": "Use the standard magnitude formula on the resulting cross product vector."}, {"id": "srs122010", "state": "AU", "section": "sr_specialist", "grade": "12", "topic": "Vectors — Cross Product", "difficulty": "hard", "style": "standard", "paper": "G12-S2", "q": "Which best describes how the magnitude of a cross product, |a×b|, relates to the parallelogram formed by vectors a and b?", "options": ["|a×b| has no geometric meaning related to area", "|a×b| equals the area of the parallelogram formed by a and b as adjacent sides", "|a×b| equals half the area of the parallelogram", "|a×b| equals the perimeter of the parallelogram"], "answer": 1, "exp": "The magnitude of the cross product |a×b| equals the area of the parallelogram formed by using a and b as adjacent sides, making the cross product a useful tool for area calculations in 3D.", "hint": "Think about the specific geometric shape formed by two vectors used as adjacent sides, and what quantity the cross product's magnitude represents for that shape."}, {"id": "srs122011", "state": "AU", "section": "sr_specialist", "grade": "12", "topic": "Vectors — Vector Equations of Lines", "difficulty": "hard", "style": "standard", "paper": "G12-S2", "q": "A line passes through the point (2, -1, 3) with direction vector (1, 2, -1). Write the vector equation of this line.", "options": ["r(t) = (2,-1,3) + t(1,2,-1)", "r(t) = (1,2,-1) + t(2,-1,3)", "r(t) = t(2,-1,3)", "r(t) = (2,-1,3) − t(1,2,-1)"], "answer": 0, "exp": "The vector equation of a line uses a known point on the line as the starting position, and the direction vector multiplied by the parameter t: r(t) = (2,-1,3) + t(1,2,-1).", "hint": "Use the known point as 'a' and the direction vector as 'd' in the standard form r(t)=a+td."}, {"id": "srs122012", "state": "AU", "section": "sr_specialist", "grade": "12", "topic": "Vectors — Parallel Lines", "difficulty": "hard", "style": "standard", "paper": "G12-S2", "q": "Two lines have direction vectors (2, 4, -2) and (1, 2, -1). What can be concluded about these two lines?", "options": ["they must intersect at a single point", "they are parallel, since (2,4,-2) = 2×(1,2,-1)", "they must be perpendicular", "no conclusion can be drawn about their relationship"], "answer": 1, "exp": "Since (2,4,-2) is exactly 2 times (1,2,-1), the two direction vectors are scalar multiples of each other, meaning the two lines are parallel (though they may or may not be the exact same line).", "hint": "Check whether one direction vector is a scalar multiple of the other."}, {"id": "srs122013", "state": "AU", "section": "sr_specialist", "grade": "12", "topic": "Vectors — Perpendicular Lines", "difficulty": "hard", "style": "standard", "paper": "G12-S2", "q": "Which best describes how to determine whether two lines (given in vector form) are perpendicular?", "options": ["check if their direction vectors are scalar multiples of each other", "check if the dot product of their direction vectors equals zero", "check if their starting points are identical", "perpendicularity cannot be determined for lines in vector form"], "answer": 1, "exp": "Two lines are perpendicular if the dot product of their direction vectors equals zero, confirming the direction vectors (and therefore the lines) are at right angles to each other.", "hint": "Recall the dot product test for perpendicularity, applied here to the lines' direction vectors."}, {"id": "srs122014", "state": "AU", "section": "sr_specialist", "grade": "12", "topic": "Vectors — Differentiating Vectors", "difficulty": "hard", "style": "standard", "paper": "G12-S2", "q": "A particle's position vector is given by r(t) = (3t, t² − 1, 2t + 1). Find the particle's velocity vector, v(t) = dr/dt.", "options": ["(3, 2t, 2)", "(3t, 2t, 2t)", "(3, t, 2)", "(0, 2t, 2)"], "answer": 0, "exp": "Differentiate each component separately: d/dt[3t]=3, d/dt[t²-1]=2t, d/dt[2t+1]=2. Combined: v(t)=(3, 2t, 2).", "hint": "Differentiate each component of the position vector separately, with respect to t."}, {"id": "srs122015", "state": "AU", "section": "sr_specialist", "grade": "12", "topic": "Vectors — Differentiating Vectors", "difficulty": "hard", "style": "standard", "paper": "G12-S2", "q": "Using v(t) = (3, 2t, 2), find the velocity vector at t = 2.", "options": ["(3, 2, 2)", "(3, 4, 2)", "(6, 4, 2)", "(3, 4, 4)"], "answer": 1, "exp": "Substituting t=2: v(2) = (3, 2×2, 2) = (3, 4, 2).", "hint": "Substitute t=2 into each component of the velocity vector."}, {"id": "srs122016", "state": "AU", "section": "sr_specialist", "grade": "12", "topic": "Vectors — Differentiating Vectors", "difficulty": "hard", "style": "standard", "paper": "G12-S2", "q": "Which best describes why differentiating a position vector with respect to time gives the velocity vector?", "options": ["this relationship is purely coincidental", "velocity is defined as the rate of change of position, and differentiation is precisely the mathematical operation that calculates a rate of change", "differentiating a vector always gives a scalar result, not velocity", "this relationship only applies to 2D vectors, not 3D"], "answer": 1, "exp": "Velocity is defined as the rate of change of position with respect to time, and differentiation is precisely the mathematical operation used to calculate a rate of change — applying it to each component of a position vector gives the velocity vector.", "hint": "Think about the fundamental definition of velocity, and how this directly corresponds to the mathematical operation of differentiation."}, {"id": "srs122017", "state": "AU", "section": "sr_specialist", "grade": "12", "topic": "Vectors — Differentiating Vectors", "difficulty": "hard", "style": "standard", "paper": "G12-S2", "q": "Given the velocity vector v(t) = (3, 2t, 2), find the acceleration vector a(t) = dv/dt.", "options": ["(0, 2, 0)", "(3, 2, 2)", "(0, t, 0)", "(3, 0, 2)"], "answer": 0, "exp": "Differentiate each component: d/dt[3]=0, d/dt[2t]=2, d/dt[2]=0. Combined: a(t)=(0, 2, 0).", "hint": "Differentiate each component of the velocity vector separately to find acceleration."}, {"id": "srs122018", "state": "AU", "section": "sr_specialist", "grade": "12", "topic": "Vectors — Integrating Vectors", "difficulty": "hard", "style": "standard", "paper": "G12-S2", "q": "Which best describes the integration of a vector function, used to find a position vector from a given velocity vector?", "options": ["integration cannot be applied to vector functions", "each component of the vector is integrated separately with respect to time, with a constant vector of integration added", "only the first component of a vector can be integrated", "integrating a velocity vector always gives an acceleration vector"], "answer": 1, "exp": "To integrate a vector function, each component is integrated separately with respect to time, with a constant vector of integration (representing initial position) added to the result.", "hint": "Think about applying the standard rules of integration to each individual component of the vector, separately."}, {"id": "srs122019", "state": "AU", "section": "sr_specialist", "grade": "12", "topic": "Vectors — Integrating Vectors", "difficulty": "hard", "style": "standard", "paper": "G12-S2", "q": "A particle has velocity v(t) = (2, 3t²) and initial position r(0) = (1, 4). Find the position vector r(t).", "options": ["r(t) = (2t+1, t³+4)", "r(t) = (2t, t³)", "r(t) = (2t+1, t³)", "r(t) = (2t, 3t³+4)"], "answer": 0, "exp": "Step 1: Integrate each component: ∫2dt=2t+C₁, ∫3t²dt=t³+C₂. Step 2: Using r(0)=(1,4): C₁=1, C₂=4. Step 3: r(t) = (2t+1, t³+4).", "hint": "Integrate each component separately, then use the initial position to find the constants of integration."}, {"id": "srs122020", "state": "AU", "section": "sr_specialist", "grade": "12", "topic": "Vectors — Concepts", "difficulty": "hard", "style": "standard", "paper": "G12-S2", "q": "Which best describes the difference between speed and velocity, when working with vectors in motion problems?", "options": ["they always have identical numerical values", "speed is the magnitude of the velocity vector (a scalar), while velocity itself is a vector with both magnitude and direction", "speed is a vector, while velocity is a scalar", "there is no meaningful difference between these two terms"], "answer": 1, "exp": "Speed is the magnitude of the velocity vector (a scalar quantity, always non-negative), while velocity itself is a vector quantity, possessing both magnitude (speed) and direction.", "hint": "Think about which quantity includes direction information, and which one is simply 'how fast', with no direction."}, {"id": "srs122021", "state": "AU", "section": "sr_specialist", "grade": "12", "topic": "Vectors — Concepts", "difficulty": "hard", "style": "standard", "paper": "G12-S2", "q": "A particle has velocity vector v(t) = (3, 4) at a particular instant. What is the particle's speed at this instant?", "options": ["3", "4", "5", "7"], "answer": 2, "exp": "Speed is the magnitude of the velocity vector: |v| = √(3²+4²) = √25 = 5.", "hint": "Find the magnitude of the velocity vector to determine the speed."}, {"id": "srs122022", "state": "AU", "section": "sr_specialist", "grade": "12", "topic": "Vectors — Skew Lines", "difficulty": "hard", "style": "standard", "paper": "G12-S2", "q": "Which best describes when two non-parallel lines in 3D space, given in vector form, would NOT intersect (described as 'skew lines')?", "options": ["this situation is impossible in 3D space — non-parallel lines must always intersect", "in 3D space, two lines can be non-parallel and still never intersect, since they may not lie in the same plane", "skew lines can only occur in 2D space", "skew lines always have identical direction vectors"], "answer": 1, "exp": "In 3D space, two lines can be non-parallel (different direction vectors) and still never intersect, since they may not lie within the same plane — these are called 'skew lines', a situation that cannot occur in 2D space.", "hint": "Think about why having more spatial dimensions (3D rather than 2D) creates new possibilities for how lines can relate to each other."}, {"id": "srs122023", "state": "AU", "section": "sr_specialist", "grade": "12", "topic": "Vectors — Vector Equations", "difficulty": "hard", "style": "standard", "paper": "G12-S2", "q": "Which best describes the geometric relationship represented by the equation |r − a| = k (a constant), where r is a position vector and a is a fixed point?", "options": ["a straight line", "a circle (in 2D) or sphere (in 3D) of radius k, centred at point a", "a single fixed point", "a parabola"], "answer": 1, "exp": "This equation describes all points r whose distance from the fixed point a is exactly k — in 2D, this forms a circle of radius k centred at a; in 3D, it forms a sphere of radius k centred at a.", "hint": "Think about what shape is formed by all points at a FIXED distance from one central point."}, {"id": "srs122024", "state": "AU", "section": "sr_specialist", "grade": "12", "topic": "Vectors — Addition", "difficulty": "hard", "style": "standard", "paper": "G12-S2", "q": "Find a + b + c using vectors a = (1, 2), b = (3, -1), and c = (-2, 4).", "options": ["(2, 5)", "(2, 6)", "(0, 5)", "(0, 6)"], "answer": 0, "exp": "Add all corresponding components: (1+3-2, 2-1+4) = (2, 5).", "hint": "Add all the corresponding x-components together, and all the corresponding y-components together."}, {"id": "srs122025", "state": "AU", "section": "sr_specialist", "grade": "12", "topic": "Vectors — Concepts", "difficulty": "hard", "style": "standard", "paper": "G12-S2", "q": "Which best describes how vector calculus (differentiating and integrating vector functions) extends single-variable calculus concepts?", "options": ["vector calculus has no real connection to single-variable calculus", "the same fundamental concepts of rate of change (differentiation) and accumulation (integration) are applied independently to each component of a vector function", "vector calculus replaces the need for single-variable calculus entirely", "differentiation and integration cannot be meaningfully applied to vectors"], "answer": 1, "exp": "Vector calculus extends single-variable calculus by applying the same fundamental concepts — rate of change (differentiation) and accumulation (integration) — independently to each component of a vector-valued function.", "hint": "Think about how the core ideas of calculus you already know get applied separately to each piece (component) of a vector."}, {"id": "srs123001", "state": "AU", "section": "sr_specialist", "grade": "12", "topic": "Mechanics — Newton's Second Law", "difficulty": "hard", "style": "standard", "paper": "G12-S3", "q": "Using Newton's second law, F = ma, find the net force required to accelerate a 5 kg object at 3 m/s².", "options": ["8 N", "12 N", "15 N", "20 N"], "answer": 2, "exp": "F = ma = 5×3 = 15 N.", "hint": "Multiply the mass by the acceleration."}, {"id": "srs123002", "state": "AU", "section": "sr_specialist", "grade": "12", "topic": "Mechanics — Equilibrium", "difficulty": "hard", "style": "standard", "paper": "G12-S3", "q": "Two forces, F₁ = (3, 4) N and F₂ = (-3, -4) N, act on an object. What is the resultant force?", "options": ["(6, 8) N", "(0, 0) N", "(-6, -8) N", "(3, 4) N"], "answer": 1, "exp": "Adding the two force vectors: (3+(-3), 4+(-4)) = (0, 0) N, meaning the object is in equilibrium.", "hint": "Add the two force vectors together component-wise."}, {"id": "srs123003", "state": "AU", "section": "sr_specialist", "grade": "12", "topic": "Mechanics — Equilibrium", "difficulty": "hard", "style": "standard", "paper": "G12-S3", "q": "Which best describes an object in 'equilibrium', in mechanics?", "options": ["an object moving at constant high speed", "an object on which the resultant (net) force is zero", "an object that has stopped permanently", "an object experiencing only one force"], "answer": 1, "exp": "An object is in equilibrium when the resultant (net) force acting on it is zero, meaning it has no acceleration (it remains at rest, or continues moving at constant velocity).", "hint": "Think about the total combined effect of all forces acting on the object — what must this equal for equilibrium?"}, {"id": "srs123004", "state": "AU", "section": "sr_specialist", "grade": "12", "topic": "Mechanics — Resultant Force", "difficulty": "hard", "style": "standard", "paper": "G12-S3", "q": "Three forces act on an object: (5,0) N, (0,12) N, and (-5,0) N. Find the resultant force.", "options": ["(0, 0) N", "(0, 12) N", "(0, 17) N", "(10, 12) N"], "answer": 1, "exp": "Adding all three force vectors: (5+0-5, 0+12+0) = (0, 12) N.", "hint": "Add all three force vectors together, component by component."}, {"id": "srs123005", "state": "AU", "section": "sr_specialist", "grade": "12", "topic": "Mechanics — Resultant Force", "difficulty": "hard", "style": "standard", "paper": "G12-S3", "q": "Using the resultant force (0, 12) N from the previous question, what is its magnitude?", "options": ["0 N", "5 N", "12 N", "17 N"], "answer": 2, "exp": "The magnitude of (0, 12) is simply √(0²+12²) = 12 N.", "hint": "Find the magnitude of the resultant vector using the standard magnitude formula."}, {"id": "srs123006", "state": "AU", "section": "sr_specialist", "grade": "12", "topic": "Mechanics — Weight", "difficulty": "hard", "style": "standard", "paper": "G12-S3", "q": "Which best describes 'weight', as distinct from 'mass', in mechanics?", "options": ["weight and mass always refer to exactly the same physical quantity", "weight is the force of gravity acting on an object's mass (calculated as W=mg), while mass is a measure of the amount of matter in an object", "mass changes depending on location, while weight never does", "weight is measured in kilograms, while mass is measured in newtons"], "answer": 1, "exp": "Weight is the force of gravity acting on an object's mass, calculated as W=mg (where g is the gravitational acceleration), while mass is a measure of the amount of matter in an object and does not change with location.", "hint": "Think about the difference between 'how much matter' an object has versus 'how strongly gravity pulls on it'."}, {"id": "srs123007", "state": "AU", "section": "sr_specialist", "grade": "12", "topic": "Mechanics — Weight", "difficulty": "hard", "style": "standard", "paper": "G12-S3", "q": "Using W = mg with g ≈ 9.8 m/s², find the weight of a 10 kg object.", "options": ["10 N", "49 N", "98 N", "980 N"], "answer": 2, "exp": "W = mg = 10×9.8 = 98 N.", "hint": "Multiply the mass by the gravitational acceleration."}, {"id": "srs123008", "state": "AU", "section": "sr_specialist", "grade": "12", "topic": "Mechanics — Inclined Planes", "difficulty": "hard", "style": "standard", "paper": "G12-S3", "q": "An object on a frictionless inclined plane at 30° to the horizontal has a weight of 50 N. Find the component of weight acting ALONG the slope (parallel to the incline).", "options": ["25 N", "43.3 N", "50 N", "57.7 N"], "answer": 0, "exp": "Step 1: Component along slope = W×sin(30°). Step 2: 50×0.5 = 25 N.", "hint": "Use the sine of the incline angle to find the component of weight acting along (parallel to) the slope."}, {"id": "srs123009", "state": "AU", "section": "sr_specialist", "grade": "12", "topic": "Mechanics — Inclined Planes", "difficulty": "hard", "style": "standard", "paper": "G12-S3", "q": "Using the same inclined plane (30°, weight 50 N), find the component of weight acting PERPENDICULAR to the slope.", "options": ["25 N", "43.3 N", "50 N", "57.7 N"], "answer": 1, "exp": "Step 1: Component perpendicular to slope = W×cos(30°). Step 2: 50×(√3/2) ≈ 43.3 N.", "hint": "Use the cosine of the incline angle to find the component of weight acting perpendicular to the slope."}, {"id": "srs123010", "state": "AU", "section": "sr_specialist", "grade": "12", "topic": "Mechanics — Inclined Planes", "difficulty": "hard", "style": "standard", "paper": "G12-S3", "q": "Which best describes why the component of weight along an inclined slope uses sine of the angle, while the perpendicular component uses cosine?", "options": ["this is purely an arbitrary convention with no geometric reason", "it follows directly from resolving the weight vector (acting vertically downward) into components parallel and perpendicular to the incline, using right-angle trigonometry based on the incline's angle", "sine and cosine are interchangeable in this context, with no real difference", "this relationship only holds for angles less than 30°"], "answer": 1, "exp": "This follows directly from resolving the weight vector (which acts vertically downward) into components parallel and perpendicular to the incline, using standard right-angle trigonometry based on the geometry created by the incline's angle.", "hint": "Think about drawing a right-angled triangle formed by the incline, and how the weight vector's components relate to the incline's angle within that triangle."}, {"id": "srs123011", "state": "AU", "section": "sr_specialist", "grade": "12", "topic": "Mechanics — Resolving Forces", "difficulty": "hard", "style": "standard", "paper": "G12-S3", "q": "A box is pulled along a horizontal surface by a force of 20 N at an angle of 30° above the horizontal. Find the horizontal component of this force.", "options": ["10 N", "17.3 N", "20 N", "23.1 N"], "answer": 1, "exp": "Step 1: Horizontal component = F×cos(30°). Step 2: 20×(√3/2) ≈ 17.3 N.", "hint": "Use the cosine of the angle to find the horizontal component of an angled force."}, {"id": "srs123012", "state": "AU", "section": "sr_specialist", "grade": "12", "topic": "Mechanics — Resolving Forces", "difficulty": "hard", "style": "standard", "paper": "G12-S3", "q": "Using the same box (20 N at 30° above horizontal), find the vertical component of this force.", "options": ["10 N", "17.3 N", "20 N", "23.1 N"], "answer": 0, "exp": "Step 1: Vertical component = F×sin(30°). Step 2: 20×0.5 = 10 N.", "hint": "Use the sine of the angle to find the vertical component of an angled force."}, {"id": "srs123013", "state": "AU", "section": "sr_specialist", "grade": "12", "topic": "Mechanics — Friction", "difficulty": "hard", "style": "standard", "paper": "G12-S3", "q": "Which best describes 'friction' as a force in mechanics?", "options": ["a force that always increases an object's speed", "a force that opposes relative motion (or attempted motion) between two surfaces in contact", "a force that only acts on objects in mid-air", "friction is not actually considered a force"], "answer": 1, "exp": "Friction is a force that opposes relative motion (or attempted motion) between two surfaces in contact, generally acting in the direction opposite to the motion (or attempted motion).", "hint": "Think about the force that resists sliding, generally acting opposite to the direction of movement."}, {"id": "srs123014", "state": "AU", "section": "sr_specialist", "grade": "12", "topic": "Mechanics — Newton's Second Law", "difficulty": "hard", "style": "standard", "paper": "G12-S3", "q": "An object of mass 4 kg experiences a net force of 12 N. Using Newton's second law, find its acceleration.", "options": ["3 m/s²", "4 m/s²", "8 m/s²", "48 m/s²"], "answer": 0, "exp": "Step 1: Rearrange F=ma to a=F/m. Step 2: a = 12/4 = 3 m/s².", "hint": "Rearrange Newton's second law to solve for acceleration, given the force and mass."}, {"id": "srs123015", "state": "AU", "section": "sr_specialist", "grade": "12", "topic": "Mechanics — Newton's Laws", "difficulty": "hard", "style": "standard", "paper": "G12-S3", "q": "Which best describes Newton's first law of motion?", "options": ["force equals mass times acceleration", "an object remains at rest, or in uniform motion in a straight line, unless acted upon by a net external force", "for every action, there is an equal and opposite reaction", "objects always accelerate when a force is applied"], "answer": 1, "exp": "Newton's first law (the law of inertia) states that an object remains at rest, or continues moving in a straight line at constant velocity, unless acted upon by a net external force.", "hint": "This is sometimes called the 'law of inertia' — think about an object's natural tendency to resist changes in its motion."}, {"id": "srs123016", "state": "AU", "section": "sr_specialist", "grade": "12", "topic": "Mechanics — Newton's Laws", "difficulty": "hard", "style": "standard", "paper": "G12-S3", "q": "Which best describes Newton's third law of motion?", "options": ["force equals mass times acceleration", "an object at rest stays at rest unless acted upon by a force", "for every action force, there is an equal and opposite reaction force", "heavier objects always experience greater acceleration"], "answer": 2, "exp": "Newton's third law states that for every action force, there is an equal and opposite reaction force, acting on the object exerting the original force.", "hint": "Think about the famous phrase describing how forces between two objects always come in equal, opposite pairs."}, {"id": "srs123017", "state": "AU", "section": "sr_specialist", "grade": "12", "topic": "Mechanics — Equilibrium", "difficulty": "hard", "style": "standard", "paper": "G12-S3", "q": "An object hangs in equilibrium, supported by two strings creating tensions T₁ = (3, 4) N and T₂. If the object's weight is (0, -10) N, find T₂, given that T₁+T₂+weight=0 for equilibrium.", "options": ["(-3, 6) N", "(3, 6) N", "(-3, -6) N", "(3, -6) N"], "answer": 0, "exp": "Step 1: For equilibrium, T₁+T₂+W=0, so T₂=-T₁-W. Step 2: T₂ = -(3,4)-(0,-10) = (-3,-4)+(0,10) = (-3, 6) N.", "hint": "Rearrange the equilibrium equation to solve for the unknown tension, carefully tracking the signs of each vector."}, {"id": "srs123018", "state": "AU", "section": "sr_specialist", "grade": "12", "topic": "Mechanics — Newton's Second Law", "difficulty": "hard", "style": "standard", "paper": "G12-S3", "q": "A car of mass 1200 kg accelerates from rest to 20 m/s in 8 seconds. Find the average net force acting on the car, assuming constant acceleration.", "options": ["1500 N", "2400 N", "3000 N", "9600 N"], "answer": 2, "exp": "Step 1: Acceleration = (20-0)/8 = 2.5 m/s². Step 2: F=ma = 1200×2.5 = 3000 N.", "hint": "Find the acceleration first using the change in velocity over time, then apply Newton's second law."}, {"id": "srs123019", "state": "AU", "section": "sr_specialist", "grade": "12", "topic": "Mechanics — Concepts", "difficulty": "hard", "style": "standard", "paper": "G12-S3", "q": "Which best describes the relationship between an object's mass and its resistance to changes in motion (its inertia)?", "options": ["mass has no connection to inertia", "a greater mass generally means greater inertia, meaning a greater force is required to produce the same acceleration", "a greater mass always means LESS inertia", "inertia only applies to objects at rest, not moving objects"], "answer": 1, "exp": "A greater mass generally means greater inertia (resistance to changes in motion), meaning a proportionally greater force is required to produce the same acceleration, consistent with Newton's second law (F=ma).", "hint": "Think about why it's harder to get a heavier object moving (or stop it), compared to a lighter one, for the same applied force."}, {"id": "srs123020", "state": "AU", "section": "sr_specialist", "grade": "12", "topic": "Mechanics — Connected Particles", "difficulty": "hard", "style": "standard", "paper": "G12-S3", "q": "Two blocks connected by a string are pulled across a frictionless surface by a horizontal force. Which best describes the tension in the connecting string, in terms of Newton's laws?", "options": ["the tension has no connection to either block's acceleration", "the tension can be found by applying Newton's second law to one of the blocks individually, considering only the forces acting on that specific block", "tension is always equal to the total applied force, regardless of the blocks' masses", "tension cannot be calculated using Newton's laws"], "answer": 1, "exp": "The tension in the connecting string can be found by applying Newton's second law to one of the blocks individually, considering only the forces acting on that specific block (including the tension itself), and using the shared acceleration of the system.", "hint": "Think about isolating just ONE block and considering only the forces acting specifically on it, including the string's tension."}, {"id": "srs123021", "state": "AU", "section": "sr_specialist", "grade": "12", "topic": "Mechanics — Connected Particles", "difficulty": "hard", "style": "standard", "paper": "G12-S3", "q": "A 2 kg block and a 3 kg block are connected by a string and pulled by a horizontal force of 20 N across a frictionless surface. Find the acceleration of the system.", "options": ["2 m/s²", "3 m/s²", "4 m/s²", "10 m/s²"], "answer": 2, "exp": "Step 1: Total mass = 2+3 = 5 kg. Step 2: Using F=ma: a = 20/5 = 4 m/s².", "hint": "Treat the connected blocks as a single system with combined mass, then apply Newton's second law."}, {"id": "srs123022", "state": "AU", "section": "sr_specialist", "grade": "12", "topic": "Mechanics — Connected Particles", "difficulty": "hard", "style": "standard", "paper": "G12-S3", "q": "Using the acceleration of 4 m/s² found previously, find the tension in the string connecting the two blocks (2 kg and 3 kg), by considering the 2 kg block alone (assuming the 20 N force is applied to the 3 kg block, pulling the 2 kg block via the string).", "options": ["6 N", "8 N", "12 N", "20 N"], "answer": 1, "exp": "Step 1: For the 2 kg block, the only horizontal force is the tension T. Step 2: Using F=ma: T = 2×4 = 8 N.", "hint": "Apply Newton's second law to just the 2 kg block, where the tension is the only force acting on it."}, {"id": "srs123023", "state": "AU", "section": "sr_specialist", "grade": "12", "topic": "Mechanics — Concepts", "difficulty": "hard", "style": "standard", "paper": "G12-S3", "q": "Which best describes why mechanics problems often resolve forces into perpendicular components (such as horizontal and vertical)?", "options": ["resolving into components has no practical benefit", "resolving forces into independent perpendicular components allows each direction to be analysed separately using simple algebra, rather than dealing with the combined vector directly", "resolving forces always changes the actual physical situation being modelled", "forces cannot be analysed at all without first resolving them"], "answer": 1, "exp": "Resolving forces into independent perpendicular components (such as horizontal and vertical) allows each direction to be analysed separately using simpler algebra and Newton's second law, rather than working with the combined vector directly in a single, more complex calculation.", "hint": "Think about why splitting a complicated angled force into two simpler, independent directions might make calculations more manageable."}, {"id": "srs123024", "state": "AU", "section": "sr_specialist", "grade": "12", "topic": "Mechanics — Projectile Motion", "difficulty": "hard", "style": "standard", "paper": "G12-S3", "q": "A projectile is launched with initial velocity components (15, 20) m/s (horizontal, vertical). Ignoring air resistance, which best describes how the horizontal and vertical motions are typically analysed?", "options": ["both directions must always be analysed together as a single combined calculation", "the horizontal and vertical motions are analysed independently, since gravity (a vertical force) does not affect the horizontal component of velocity", "gravity affects both directions equally and identically", "the horizontal velocity always decreases the same way the vertical velocity does"], "answer": 1, "exp": "In projectile motion (ignoring air resistance), the horizontal and vertical motions are analysed independently, since gravity (acting vertically) does not affect the horizontal component of velocity, which remains constant throughout the flight.", "hint": "Think about which direction gravity actually acts in, and why this means it only affects ONE of the two velocity components."}, {"id": "srs123025", "state": "AU", "section": "sr_specialist", "grade": "12", "topic": "Mechanics — Projectile Motion", "difficulty": "hard", "style": "standard", "paper": "G12-S3", "q": "For the projectile with initial vertical velocity 20 m/s (taking up as positive, g≈9.8 m/s² acting downward), find the time taken to reach its maximum height (where vertical velocity becomes momentarily zero).", "options": ["about 1.0 s", "about 2.0 s", "about 3.0 s", "about 4.0 s"], "answer": 1, "exp": "Step 1: Using v=u+at, with final vertical velocity v=0: 0=20−9.8t. Step 2: t=20/9.8 ≈ 2.0 s.", "hint": "Use the equation of motion v=u+at, setting the final vertical velocity to zero (the condition at maximum height)."}, {"id": "srs124001", "state": "AU", "section": "sr_specialist", "grade": "12", "topic": "Calculus — Implicit Differentiation", "difficulty": "hard", "style": "standard", "paper": "G12-S4", "q": "Using implicit differentiation, find dy/dx for the equation x² + y² = 25.", "options": ["dy/dx = x/y", "dy/dx = -x/y", "dy/dx = y/x", "dy/dx = -y/x"], "answer": 1, "exp": "Step 1: Differentiate both sides with respect to x: 2x + 2y(dy/dx) = 0. Step 2: Solve for dy/dx: dy/dx = -x/y.", "hint": "Differentiate each term with respect to x, remembering to apply the chain rule to y² (treating y as a function of x)."}, {"id": "srs124002", "state": "AU", "section": "sr_specialist", "grade": "12", "topic": "Calculus — Implicit Differentiation", "difficulty": "hard", "style": "standard", "paper": "G12-S4", "q": "Using dy/dx = -x/y for the circle x² + y² = 25, find the gradient of the curve at the point (3, 4).", "options": ["3/4", "-3/4", "4/3", "-4/3"], "answer": 1, "exp": "Substituting x=3, y=4 into dy/dx=-x/y: -3/4.", "hint": "Substitute the given point's coordinates directly into the implicit derivative."}, {"id": "srs124003", "state": "AU", "section": "sr_specialist", "grade": "12", "topic": "Calculus — Implicit Differentiation", "difficulty": "hard", "style": "standard", "paper": "G12-S4", "q": "Using implicit differentiation, find dy/dx for the equation xy = 10.", "options": ["dy/dx = y/x", "dy/dx = -y/x", "dy/dx = x/y", "dy/dx = -x/y"], "answer": 1, "exp": "Step 1: Apply the product rule to differentiate xy: y + x(dy/dx) = 0. Step 2: Solve for dy/dx: dy/dx = -y/x.", "hint": "Use the product rule on the left side, since both x and y depend on x, then solve for dy/dx."}, {"id": "srs124004", "state": "AU", "section": "sr_specialist", "grade": "12", "topic": "Calculus — Implicit Differentiation", "difficulty": "hard", "style": "standard", "paper": "G12-S4", "q": "Using dy/dx = -y/x for xy=10, find the gradient at the point (2, 5).", "options": ["5/2", "-5/2", "2/5", "-2/5"], "answer": 1, "exp": "Substituting x=2, y=5 into dy/dx=-y/x: -5/2.", "hint": "Substitute the given point's coordinates directly into the implicit derivative."}, {"id": "srs124005", "state": "AU", "section": "sr_specialist", "grade": "12", "topic": "Calculus — Related Rates", "difficulty": "hard", "style": "standard", "paper": "G12-S4", "q": "A spherical balloon's volume is given by V = (4/3)πr³. Find dV/dr.", "options": ["4πr", "4πr²", "(4/3)πr²", "(4/3)πr"], "answer": 1, "exp": "Differentiate V with respect to r: dV/dr = (4/3)π × 3r² = 4πr².", "hint": "Apply the power rule to differentiate the volume formula with respect to r."}, {"id": "srs124006", "state": "AU", "section": "sr_specialist", "grade": "12", "topic": "Calculus — Related Rates", "difficulty": "hard", "style": "standard", "paper": "G12-S4", "q": "A spherical balloon is being inflated so that its radius increases at a rate of 2 cm/s. When the radius is 5 cm, find the rate of change of volume, dV/dt, using dV/dt = dV/dr × dr/dt.", "options": ["40π cm³/s", "100π cm³/s", "200π cm³/s", "400π cm³/s"], "answer": 2, "exp": "Step 1: dV/dr = 4πr² = 4π(5)² = 100π. Step 2: dV/dt = dV/dr × dr/dt = 100π × 2 = 200π cm³/s.", "hint": "Find dV/dr at the given radius first, then multiply by the given dr/dt using the chain rule for related rates."}, {"id": "srs124007", "state": "AU", "section": "sr_specialist", "grade": "12", "topic": "Calculus — Related Rates", "difficulty": "hard", "style": "standard", "paper": "G12-S4", "q": "Which best describes the 'chain rule' approach used in related rates problems, such as dV/dt = (dV/dr)(dr/dt)?", "options": ["this approach has no connection to the standard chain rule used elsewhere in calculus", "it applies the same chain rule principle used in differentiation, linking the rate of change of one quantity to another through a shared, related variable", "related rates problems never actually use the chain rule", "this formula only works for spheres, not other shapes"], "answer": 1, "exp": "Related rates problems apply the same chain rule principle used elsewhere in differentiation, linking the rate of change of one quantity (like volume) to another (like time) through a shared, related variable (like radius).", "hint": "Think about how this formula connects two rates of change through a common 'in-between' variable, similar to how the chain rule connects nested functions."}, {"id": "srs124008", "state": "AU", "section": "sr_specialist", "grade": "12", "topic": "Calculus — Related Rates", "difficulty": "hard", "style": "standard", "paper": "G12-S4", "q": "A 10 m ladder leans against a wall, with its base sliding away from the wall at 2 m/s. Using x²+y²=100 (where x is the distance from the wall and y is the height up the wall), find dy/dx at the point where x=6, y=8.", "options": ["-4/3", "-3/4", "3/4", "4/3"], "answer": 1, "exp": "Step 1: Implicit differentiation of x²+y²=100 gives dy/dx=-x/y. Step 2: At x=6, y=8: dy/dx=-6/8=-3/4.", "hint": "Use implicit differentiation on the ladder equation, then substitute the given x and y values."}, {"id": "srs124009", "state": "AU", "section": "sr_specialist", "grade": "12", "topic": "Calculus — Related Rates", "difficulty": "hard", "style": "standard", "paper": "G12-S4", "q": "Using dy/dx=-3/4 (from the previous question) and dx/dt=2 m/s (the rate the base slides away from the wall), find dy/dt (the rate the top of the ladder slides down the wall), using dy/dt = (dy/dx)(dx/dt).", "options": ["-2 m/s", "-3/2 m/s", "3/2 m/s", "2 m/s"], "answer": 1, "exp": "Step 1: dy/dt = dy/dx × dx/dt = (-3/4)×2. Step 2: -3/2 m/s (the negative sign indicates the top of the ladder is sliding DOWN the wall).", "hint": "Multiply the gradient dy/dx by the given rate dx/dt to find dy/dt, using the chain rule for related rates."}, {"id": "srs124010", "state": "AU", "section": "sr_specialist", "grade": "12", "topic": "Calculus — Related Rates", "difficulty": "hard", "style": "standard", "paper": "G12-S4", "q": "Which best describes the typical first step when solving a related rates problem?", "options": ["immediately substitute all given numerical values before any differentiation", "identify an equation relating the relevant variables, then differentiate this equation with respect to time (using implicit differentiation where needed)", "skip differentiation entirely and use algebra alone", "always assume the rates of change are constant throughout the problem"], "answer": 1, "exp": "The typical first step is to identify an equation relating the relevant variables (such as a geometric formula), then differentiate this equation with respect to time using implicit differentiation, before substituting specific numerical values.", "hint": "Think about establishing the mathematical RELATIONSHIP between the variables first, before bringing in any specific numbers."}, {"id": "srs124011", "state": "AU", "section": "sr_specialist", "grade": "12", "topic": "Calculus — Related Rates", "difficulty": "hard", "style": "standard", "paper": "G12-S4", "q": "A cube's volume V = x³ (where x is the side length) is increasing at a rate of dV/dt = 12 cm³/s. When x = 2 cm, find dx/dt using dV/dt = 3x²(dx/dt).", "options": ["0.5 cm/s", "1 cm/s", "2 cm/s", "4 cm/s"], "answer": 1, "exp": "Step 1: dV/dt = 3x²(dx/dt), so 12 = 3(2)²(dx/dt) = 12(dx/dt). Step 2: dx/dt = 12/12 = 1 cm/s.", "hint": "Substitute the known values into the related rates equation, then solve for the unknown rate."}, {"id": "srs124012", "state": "AU", "section": "sr_specialist", "grade": "12", "topic": "Calculus — Implicit Differentiation", "difficulty": "hard", "style": "standard", "paper": "G12-S4", "q": "Using implicit differentiation, find dy/dx for x² + 4y² = 16.", "options": ["dy/dx = -x/(4y)", "dy/dx = -4x/y", "dy/dx = x/(4y)", "dy/dx = -x/y"], "answer": 0, "exp": "Step 1: Differentiate both sides: 2x + 8y(dy/dx) = 0. Step 2: Solve for dy/dx: dy/dx = -2x/(8y) = -x/(4y).", "hint": "Differentiate both sides with respect to x, then carefully solve for dy/dx, simplifying the resulting fraction."}, {"id": "srs124013", "state": "AU", "section": "sr_specialist", "grade": "12", "topic": "Calculus — Implicit Differentiation", "difficulty": "hard", "style": "standard", "paper": "G12-S4", "q": "Which best describes why implicit differentiation is necessary for equations like x² + y² = 25, rather than simply differentiating as if y were a constant?", "options": ["implicit differentiation is never actually necessary for such equations", "since y is itself a function of x (even though it's not explicitly solved for), differentiating y² requires the chain rule, treating y as a function of x", "this equation cannot be differentiated by any method", "y must be solved for explicitly before any differentiation can occur"], "answer": 1, "exp": "Since y is itself implicitly a function of x (even though the equation isn't explicitly solved for y), differentiating any term containing y requires the chain rule, treating y as a function of x rather than as a constant.", "hint": "Think about why y² needs special treatment when y itself depends on x, even if that dependence isn't written out explicitly."}, {"id": "srs124014", "state": "AU", "section": "sr_specialist", "grade": "12", "topic": "Calculus — Related Rates", "difficulty": "hard", "style": "standard", "paper": "G12-S4", "q": "A cylindrical tank's volume is V = πr²h, where r is fixed at 3 m and h changes over time. Find dV/dt in terms of dh/dt.", "options": ["dV/dt = 3πr(dh/dt)", "dV/dt = πr²(dh/dt)", "dV/dt = 2πrh(dh/dt)", "dV/dt = πr(dh/dt)"], "answer": 1, "exp": "Since r is fixed (constant), differentiating V=πr²h with respect to time (treating πr² as a constant coefficient) gives dV/dt = πr²(dh/dt).", "hint": "Since r is fixed, treat πr² as a constant when differentiating V with respect to time."}, {"id": "srs124015", "state": "AU", "section": "sr_specialist", "grade": "12", "topic": "Calculus — Related Rates", "difficulty": "hard", "style": "standard", "paper": "G12-S4", "q": "Using dV/dt = πr²(dh/dt) with r=3 m, if water is being pumped into the tank at dV/dt = 18π m³/min, find dh/dt.", "options": ["1 m/min", "2 m/min", "3 m/min", "6 m/min"], "answer": 1, "exp": "Step 1: 18π = π(3)²(dh/dt) = 9π(dh/dt). Step 2: dh/dt = 18π/9π = 2 m/min.", "hint": "Substitute the known values into the related rates equation, then solve for dh/dt."}, {"id": "srs124016", "state": "AU", "section": "sr_specialist", "grade": "12", "topic": "Calculus — Implicit Differentiation", "difficulty": "hard", "style": "standard", "paper": "G12-S4", "q": "Using implicit differentiation, find dy/dx for the equation y³ + x² = 10, then evaluate at the point (1, 2) (Hint: differentiate y³ using the chain rule, giving 3y²(dy/dx)).", "options": ["-1/6", "-1/12", "1/12", "1/6"], "answer": 0, "exp": "Step 1: Differentiate: 3y²(dy/dx) + 2x = 0, so dy/dx = -2x/(3y²). Step 2: At (1,2): dy/dx = -2(1)/(3(2)²) = -2/12 = -1/6.", "hint": "Differentiate using the chain rule for y³, solve for dy/dx, then substitute the given point."}, {"id": "srs124017", "state": "AU", "section": "sr_specialist", "grade": "12", "topic": "Calculus — Related Rates", "difficulty": "hard", "style": "standard", "paper": "G12-S4", "q": "Which best describes a practical application of related rates in real-world problems?", "options": ["related rates have no practical application beyond theoretical mathematics", "related rates can model situations where multiple changing quantities are connected, such as how fast a shadow's length changes as a person walks away from a light source", "related rates can only be applied to geometric shapes like spheres and cubes", "related rates problems always require exactly two related variables, never more"], "answer": 1, "exp": "Related rates can model many real-world situations where multiple changing quantities are mathematically connected, such as how fast a shadow's length changes as a person walks away from a light source, or how fast water level changes as a tank drains.", "hint": "Think about everyday situations where one changing quantity (like distance walked) might be mathematically linked to another changing quantity (like shadow length)."}, {"id": "srs124018", "state": "AU", "section": "sr_specialist", "grade": "12", "topic": "Calculus — Related Rates", "difficulty": "hard", "style": "standard", "paper": "G12-S4", "q": "A person 1.8 m tall walks away from a 6 m lamppost at 1.5 m/s. Using similar triangles, the shadow length s relates to the person's distance from the lamppost, x, by the equation s/1.8 = (x+s)/6. Simplifying gives 6s=1.8x+1.8s, or 4.2s=1.8x. Find ds/dt in terms of dx/dt.", "options": ["ds/dt = (1.8/4.2)(dx/dt)", "ds/dt = (4.2/1.8)(dx/dt)", "ds/dt = 1.8(dx/dt)", "ds/dt = 4.2(dx/dt)"], "answer": 0, "exp": "Differentiating 4.2s=1.8x with respect to time: 4.2(ds/dt)=1.8(dx/dt), so ds/dt = (1.8/4.2)(dx/dt).", "hint": "Differentiate the simplified linear equation with respect to time, then solve for ds/dt."}, {"id": "srs124019", "state": "AU", "section": "sr_specialist", "grade": "12", "topic": "Calculus — Related Rates", "difficulty": "hard", "style": "standard", "paper": "G12-S4", "q": "Using ds/dt = (1.8/4.2)(dx/dt) and dx/dt = 1.5 m/s, find the rate at which the shadow's length is increasing.", "options": ["about 0.43 m/s", "about 0.64 m/s", "about 1.5 m/s", "about 3.5 m/s"], "answer": 1, "exp": "Step 1: ds/dt = (1.8/4.2)×1.5. Step 2: This gives approximately 0.643 m/s, which rounds to about 0.64 m/s.", "hint": "Substitute the given rate into the related rates equation found previously."}, {"id": "srs124020", "state": "AU", "section": "sr_specialist", "grade": "12", "topic": "Calculus — Implicit Differentiation", "difficulty": "hard", "style": "standard", "paper": "G12-S4", "q": "Using implicit differentiation, find dy/dx for x² + y² + 2x = 5.", "options": ["dy/dx = -(x+1)/y", "dy/dx = -(2x+2)/y", "dy/dx = (x+1)/y", "dy/dx = -x/y"], "answer": 0, "exp": "Step 1: Differentiate: 2x+2y(dy/dx)+2=0. Step 2: Solve: dy/dx = -(2x+2)/(2y) = -(x+1)/y.", "hint": "Differentiate each term carefully, including the constant coefficient on the linear x term, then solve for dy/dx and simplify."}, {"id": "srs124021", "state": "AU", "section": "sr_specialist", "grade": "12", "topic": "Calculus — Related Rates", "difficulty": "hard", "style": "standard", "paper": "G12-S4", "q": "Which best describes why related rates problems typically require differentiating an equation with respect to TIME, even when time doesn't explicitly appear in the original equation?", "options": ["time must always be explicitly written into the original equation before differentiating", "since the variables in the equation (like radius or volume) are themselves changing as functions of time, differentiating with respect to time captures how the whole equation changes as time progresses", "differentiating with respect to time is mathematically meaningless if time isn't in the equation", "related rates problems never actually involve differentiating with respect to time"], "answer": 1, "exp": "Since the variables in the equation (such as radius or volume) are themselves implicitly functions of time (even if 't' isn't explicitly written), differentiating the entire equation with respect to time captures how all the related quantities change together as time progresses.", "hint": "Think about how each variable in the equation is secretly a function of time, even if 't' never appears directly in the written equation."}, {"id": "srs124022", "state": "AU", "section": "sr_specialist", "grade": "12", "topic": "Calculus — Related Rates", "difficulty": "hard", "style": "standard", "paper": "G12-S4", "q": "A circular oil spill's area is given by A = πr². If the radius is increasing at 0.5 m/min, find dA/dt when r = 10 m, using dA/dt = 2πr(dr/dt).", "options": ["5π m²/min", "10π m²/min", "20π m²/min", "100π m²/min"], "answer": 1, "exp": "Step 1: dA/dt = 2πr(dr/dt) = 2π(10)(0.5). Step 2: This gives 10π m²/min.", "hint": "Substitute the given radius and rate of change of radius into the related rates formula."}, {"id": "srs124023", "state": "AU", "section": "sr_specialist", "grade": "12", "topic": "Calculus — Implicit Differentiation", "difficulty": "hard", "style": "standard", "paper": "G12-S4", "q": "Which best describes the key difference between explicit and implicit differentiation?", "options": ["they always give different, contradictory results for the same relationship", "explicit differentiation is used when y is already isolated as a function of x, while implicit differentiation is used when the relationship between x and y is given without y being isolated", "implicit differentiation can only be used for circles", "explicit differentiation cannot handle any equation with more than one variable"], "answer": 1, "exp": "Explicit differentiation is used when y is already isolated as a function of x (e.g. y=x²), while implicit differentiation is used when the relationship between x and y is given without y being explicitly isolated (e.g. x²+y²=25) — both approaches, when applicable, give consistent, equivalent results.", "hint": "Think about whether y has already been solved for in terms of x, or whether x and y remain mixed together in the same equation."}, {"id": "srs124024", "state": "AU", "section": "sr_specialist", "grade": "12", "topic": "Calculus — Implicit Differentiation", "difficulty": "hard", "style": "standard", "paper": "G12-S4", "q": "For the implicit equation x² + y² = 25, at the point where y = 0 (i.e. x = ±5), what happens to the implicit derivative dy/dx = -x/y?", "options": ["dy/dx equals exactly 0 at this point", "dy/dx is undefined at this point, since this would require dividing by zero", "dy/dx equals exactly 1 at this point", "dy/dx cannot be determined using implicit differentiation at this point"], "answer": 1, "exp": "At y=0, the formula dy/dx=-x/y would require dividing by zero, making the derivative undefined at this point — geometrically, this corresponds to a vertical tangent line at (5,0) and (-5,0) on the circle.", "hint": "Think about what happens mathematically when the denominator of this implicit derivative formula equals zero."}, {"id": "srs124025", "state": "AU", "section": "sr_specialist", "grade": "12", "topic": "Calculus — Related Rates", "difficulty": "hard", "style": "standard", "paper": "G12-S4", "q": "A rectangular garden's length is increasing at 3 m/min and its width is increasing at 2 m/min. When length=10 m and width=6 m, find dA/dt, the rate of change of area, using A=LW and the product rule dA/dt = L(dW/dt) + W(dL/dt).", "options": ["38 m²/min", "48 m²/min", "50 m²/min", "56 m²/min"], "answer": 0, "exp": "Step 1: dA/dt = L(dW/dt) + W(dL/dt) = 10(2) + 6(3). Step 2: 20+18 = 38 m²/min.", "hint": "Apply the product rule for related rates, substituting the given lengths, widths, and their individual rates of change."}];